    // Spawn the inbound external event source supervisor (#833, Phase D).
    // Opt-in via INBOUND_EXTERNAL_SOURCES_ENABLED (default false / standby cost
    // gate). The connector registry is empty until concrete connectors register
    // their kind (#834 redis-stream, #835 sse, #836 kafka); enabled sources of
    // unregistered kinds are skipped with a warning.
    if std::env::var("INBOUND_EXTERNAL_SOURCES_ENABLED")
        .map(|v| v == "true" || v == "1")
        .unwrap_or(false)
    {
        let supervisor = std::sync::Arc::new(matric_jobs::inbound::InboundSupervisor::new(
            state.db.clone(),
            state.inbound_metrics.clone(),
        ));
        let mut registry = matric_jobs::inbound::SourceRegistry::new();
        // Register concrete connector kinds. redis-stream (#834) and sse (#835)
        // are live; kafka (#836) registers here as it lands.
        registry.register(
            "redis-stream",
            Box::new(|name, config| {
                matric_jobs::inbound::RedisStreamSource::from_config(name, config)
                    .map(|s| Box::new(s) as Box<dyn matric_jobs::inbound::InboundEventSource>)
            }),
        );
        registry.register(
            "sse",
            Box::new(|name, config| {
                matric_jobs::inbound::SseSource::from_config(name, config)
                    .map(|s| Box::new(s) as Box<dyn matric_jobs::inbound::InboundEventSource>)
            }),
        );
        // Kafka (#836): compiled only with the `kafka` feature AND runtime-gated
        // by INBOUND_KAFKA_ENABLED (default false) per the Phase D cost-gate.
        #[cfg(feature = "kafka")]
        {
            if std::env::var("INBOUND_KAFKA_ENABLED")
                .map(|v| v == "true" || v == "1")
                .unwrap_or(false)
            {
                registry.register(
                    "kafka",
                    Box::new(|name, config| {
                        matric_jobs::inbound::KafkaSource::from_config(name, config).map(|s| {
                            Box::new(s) as Box<dyn matric_jobs::inbound::InboundEventSource>
                        })
                    }),
                );
                info!("inbound: kafka connector kind enabled (INBOUND_KAFKA_ENABLED)");
            }
        }
        info!("Starting inbound event source supervisor (Phase D)...");
        let _handles = supervisor.start_from_registry(&registry).await;
    }

    // Spawn periodic inference reachability probe (#630).
    // Re-probes the generation backend at a fixed interval so `capabilities.chat.available`
    // and `capabilities.inference.available` track the provider's live state — recovering
    // automatically when a provider (e.g. Ollama) becomes reachable after Fortemi startup.
    {
        let probe_interval_secs: u64 = std::env::var("INFERENCE_PROBE_INTERVAL_SECS")
            .ok()
            .and_then(|v| v.parse().ok())
            .filter(|&v: &u64| v > 0)
            .unwrap_or(30);
        let runtime = state.inference_runtime.clone();
        let flag = inference_available.clone();
        let bus = state.event_bus.clone();
        info!(
            interval_secs = probe_interval_secs,
            "Starting periodic inference reachability probe (#630)"
        );
        tokio::spawn(async move {
            inference_reachability_probe(runtime, flag, bus, probe_interval_secs).await;
        });
    }

