#[utoipa::path(post, path = "/api/v1/webhooks/{id}/test", tag = "Webhooks",
    params(("id" = Uuid, Path, description = "Webhook ID")),
    responses((status = 200, description = "Success")))]
async fn test_webhook(
    auth: Auth,
    State(state): State<AppState>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let webhook = state
        .db
        .webhooks
        .get(id)
        .await?
        .ok_or_else(webhook_not_found)?;

    let webhook_timeout = std::env::var("MATRIC_WEBHOOK_TIMEOUT_SECS")
        .ok()
        .and_then(|v| v.parse::<u64>().ok())
        .unwrap_or(matric_core::defaults::WEBHOOK_TIMEOUT_SECS);

    let test_event = ServerEvent::QueueStatus {
        total_jobs: 0,
        running: 0,
        pending: 0,
    };
    let payload = serde_json::to_value(&test_event).unwrap_or_default();

    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(webhook_timeout))
        .build()
        .unwrap_or_default();

    deliver_webhook(&client, &state.db, &webhook, "test", &payload).await;
    emit_webhook_control_audit_event(webhook_control_audit_event(
        &auth,
        "subscription_test",
        AuditOutcome::Success,
        webhook.id,
        webhook.events.len(),
        webhook.is_active,
        webhook
            .secret
            .as_ref()
            .is_some_and(|secret| !secret.is_empty()),
        Some(webhook.max_retries),
        None,
    ))
    .await;

    Ok(Json(serde_json::json!({ "status": "delivered" })))
}

async fn emit_webhook_control_audit_event(event: AuditEvent) {
    if let Err(err) = TracingSink.emit(event).await {
        warn!(
            error_len = telemetry_text_len(&err.to_string()),
            detail = API_AUDIT_EMIT_DIAGNOSTIC_FAILURE_DETAIL,
            operation = "emit_webhook_control_audit_event",
            "failed to emit webhook control audit event"
        );
    }
}

async fn emit_incoming_webhook_audit_event(event: AuditEvent) {
    if let Err(err) = TracingSink.emit(event).await {
        warn!(
            error_len = telemetry_text_len(&err.to_string()),
            detail = API_AUDIT_EMIT_DIAGNOSTIC_FAILURE_DETAIL,
            operation = "emit_incoming_webhook_audit_event",
            "failed to emit incoming webhook audit event"
        );
    }
}

fn webhook_control_audit_event(
    auth: &Auth,
    action: &str,
    outcome: AuditOutcome,
    webhook_id: Uuid,
    event_count: usize,
    is_active: bool,
    secret_set: bool,
    max_retries: Option<i32>,
    reason: Option<&str>,
) -> AuditEvent {
    let mut event = AuditEvent::new("webhook", action, outcome)
        .with_principal(auth_principal_audit_id(&auth.principal))
        .with_resource("webhook", webhook_id.to_string())
        .with_attr("webhook_event_count", event_count as i64)
        .with_attr("webhook_is_active", is_active)
        .with_attr("webhook_secret_set", secret_set);

    if let Some(max_retries) = max_retries {
        event = event.with_attr("webhook_max_retries", max_retries);
    }
    if let Some(reason) = reason {
        event.reason = Some(reason.to_string());
        event = event.with_attr("reason_code", reason.to_string());
    }

    event.source = AuditSource::Api;
    event.visibility = AuditVisibilityClass::SecurityRestricted;
    event.failure_policy = AuditFailurePolicy::BestEffort;
    event.severity = match outcome {
        AuditOutcome::Success => AuditSeverity::Info,
        AuditOutcome::Denied => AuditSeverity::Warn,
        AuditOutcome::Failure | AuditOutcome::Error => AuditSeverity::Error,
        AuditOutcome::Unknown => AuditSeverity::Warn,
    };
    event.sanitized()
}

fn incoming_webhook_signature_header_class(signature_header: &str) -> &'static str {
    if signature_header.eq_ignore_ascii_case("X-Twilio-Signature") {
        "twilio"
    } else {
        "hmac_sha256"
    }
}

fn incoming_webhook_decision_audit_event(
    receiver: &matric_core::IncomingWebhookReceiver,
    action: &str,
    outcome: AuditOutcome,
    reason: Option<&str>,
    body_len: usize,
    idempotency_key_present: bool,
) -> AuditEvent {
    let mut event = AuditEvent::new("webhook", action, outcome)
        .with_resource("incoming_webhook_receiver", receiver.id.to_string())
        .with_attr("receiver_slug_len", receiver.slug.chars().count() as i64)
        .with_attr("provider", receiver.provider.clone())
        .with_attr("schema_ref", receiver.schema_ref.clone())
        .with_attr(
            "signature_header_class",
            incoming_webhook_signature_header_class(&receiver.signature_header),
        )
        .with_attr("receiver_is_active", receiver.is_active)
        .with_attr("receiver_secret_set", receiver.secret_set)
        .with_attr("request_body_len", body_len as i64)
        .with_attr("idempotency_key_present", idempotency_key_present);

    if let Some(reason) = reason {
        event.reason = Some(reason.to_string());
        event = event.with_attr("reason_code", reason.to_string());
    }

    event.source = AuditSource::Api;
    event.visibility = AuditVisibilityClass::SecurityRestricted;
    event.failure_policy = AuditFailurePolicy::BestEffort;
    event.severity = match outcome {
        AuditOutcome::Success => AuditSeverity::Info,
        AuditOutcome::Denied => AuditSeverity::Warn,
        AuditOutcome::Failure | AuditOutcome::Error => AuditSeverity::Error,
        AuditOutcome::Unknown => AuditSeverity::Warn,
    };
    event.sanitized()
}

fn incoming_webhook_signature_error_reason(err: &ApiError) -> &'static str {
    match err {
        ApiError::Unauthorized(message)
            if message.contains("missing incoming webhook signature") =>
        {
            "signature_missing"
        }
        ApiError::Unauthorized(message)
            if message.contains("unsupported incoming webhook signature format") =>
        {
            "signature_format_unsupported"
        }
        ApiError::Unauthorized(message)
            if message.contains("invalid incoming webhook signature encoding") =>
        {
            "signature_encoding_invalid"
        }
        ApiError::Unauthorized(message)
            if message.contains("invalid incoming webhook signature secret") =>
        {
            "signature_secret_invalid"
        }
        ApiError::Unauthorized(message)
            if message.contains("missing incoming webhook request URL") =>
        {
            "request_url_missing"
        }
        ApiError::Unauthorized(message)
            if message.contains("invalid Twilio webhook form parameters") =>
        {
            "twilio_form_invalid"
        }
        ApiError::Unauthorized(message)
            if message.contains("invalid incoming webhook signature") =>
        {
            "signature_invalid"
        }
        ApiError::Unauthorized(_) => "signature_denied",
        _ => "signature_error",
    }
}

fn verify_incoming_signature(
    headers: &HeaderMap,
    signature_header: &str,
    secret: &str,
    body: &[u8],
    uri: Option<&Uri>,
) -> Result<(), ApiError> {
    if signature_header.eq_ignore_ascii_case("X-Twilio-Signature") {
        return verify_twilio_incoming_signature(headers, secret, body, uri);
    }

    use hmac::{Hmac, Mac};
    use sha2::Sha256;
    type HmacSha256 = Hmac<Sha256>;

    let signature = headers
        .get(signature_header)
        .and_then(|value| value.to_str().ok())
        .ok_or_else(|| ApiError::Unauthorized("missing incoming webhook signature".to_string()))?;
    let signature = signature.strip_prefix("sha256=").ok_or_else(|| {
        ApiError::Unauthorized("unsupported incoming webhook signature format".to_string())
    })?;
    let signature = hex::decode(signature).map_err(|_| {
        ApiError::Unauthorized("invalid incoming webhook signature encoding".to_string())
    })?;

    let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).map_err(|_| {
        ApiError::Unauthorized("invalid incoming webhook signature secret".to_string())
    })?;
    mac.update(body);
    mac.verify_slice(&signature)
        .map_err(|_| ApiError::Unauthorized("invalid incoming webhook signature".to_string()))
}

fn verify_twilio_incoming_signature(
    headers: &HeaderMap,
    secret: &str,
    body: &[u8],
    uri: Option<&Uri>,
) -> Result<(), ApiError> {
    use hmac::{Hmac, Mac};
    use sha1::Sha1;

    type HmacSha1 = Hmac<Sha1>;

    let signature = headers
        .get("X-Twilio-Signature")
        .and_then(|value| value.to_str().ok())
        .ok_or_else(|| ApiError::Unauthorized("missing incoming webhook signature".to_string()))?;
    let expected_url = incoming_webhook_external_url(headers, uri).ok_or_else(|| {
        ApiError::Unauthorized("missing incoming webhook request URL".to_string())
    })?;
    let mut params: Vec<(String, String)> = serde_urlencoded::from_bytes(body).map_err(|_| {
        ApiError::Unauthorized("invalid Twilio webhook form parameters".to_string())
    })?;
    params.sort_by(|left, right| left.0.cmp(&right.0).then_with(|| left.1.cmp(&right.1)));

    let mut payload = expected_url;
    for (key, value) in params {
        payload.push_str(&key);
        payload.push_str(&value);
    }

    let mut mac = HmacSha1::new_from_slice(secret.as_bytes()).map_err(|_| {
        ApiError::Unauthorized("invalid incoming webhook signature secret".to_string())
    })?;
    mac.update(payload.as_bytes());
    let signature = base64::engine::general_purpose::STANDARD
        .decode(signature)
        .map_err(|_| {
            ApiError::Unauthorized("invalid incoming webhook signature encoding".to_string())
        })?;
    mac.verify_slice(&signature)
        .map_err(|_| ApiError::Unauthorized("invalid incoming webhook signature".to_string()))
}

fn incoming_webhook_external_url(headers: &HeaderMap, uri: Option<&Uri>) -> Option<String> {
    let uri = uri?;
    if uri.scheme().is_some() && uri.authority().is_some() {
        return Some(uri.to_string());
    }

    let proto = header_str(headers, "X-Forwarded-Proto")
        .or_else(|| header_str(headers, "X-Forwarded-Protocol"))
        .unwrap_or("https");
    let host = header_str(headers, "X-Forwarded-Host").or_else(|| header_str(headers, "Host"))?;
    Some(format!("{proto}://{host}{uri}"))
}

fn header_str<'a>(headers: &'a HeaderMap, name: &str) -> Option<&'a str> {
    headers
        .get(name)
        .and_then(|value| value.to_str().ok())
        .and_then(|value| value.split(',').next())
        .map(str::trim)
        .filter(|value| !value.is_empty())
}

fn incoming_payload_from_body(
    schema_ref: &str,
    content_type: Option<&HeaderValue>,
    body: &[u8],
) -> Result<serde_json::Value, ApiError> {
    let content_type = content_type
        .and_then(|value| value.to_str().ok())
        .unwrap_or_default();

    if content_type.starts_with("application/x-www-form-urlencoded")
        || schema_ref == "twilio.voice.v1"
    {
        let fields: std::collections::BTreeMap<String, String> = serde_urlencoded::from_bytes(body)
            .map_err(|_| ApiError::BadRequest("Invalid form webhook payload.".to_string()))?;
        return serde_json::to_value(fields)
            .map_err(|_| ApiError::BadRequest("Invalid webhook payload.".to_string()));
    }

    serde_json::from_slice(body)
        .map_err(|_| ApiError::BadRequest("Invalid JSON webhook payload.".to_string()))
}

