#[utoipa::path(post, path = "/api/v1/webhooks/incoming/{slug}", tag = "Incoming Webhooks",
    params(("slug" = String, Path, description = "Incoming receiver slug")),
    request_body(content = String, content_type = "application/octet-stream"),
    responses(
        (status = 200, description = "Accepted"),
        (status = 400, description = "Schema validation failure"),
        (status = 401, description = "Missing or invalid signature"),
        (status = 404, description = "Unknown receiver slug")
    ))]
async fn receive_incoming_webhook(
    State(state): State<AppState>,
    OriginalUri(uri): OriginalUri,
    Path(slug): Path<String>,
    headers: HeaderMap,
    body: Bytes,
) -> Result<impl IntoResponse, ApiError> {
    let receiver = state
        .db
        .incoming_webhooks
        .get_by_slug(&slug)
        .await?
        .ok_or_else(incoming_webhook_receiver_not_found)?;
    if !receiver.is_active {
        emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
            &receiver,
            "receiver_active_check",
            AuditOutcome::Denied,
            Some("receiver_inactive"),
            body.len(),
            headers.get("idempotency-key").is_some(),
        ))
        .await;
        return Err(incoming_webhook_receiver_not_found());
    }

    let secret = match state
        .db
        .incoming_webhooks
        .get_active_secret_by_slug(&slug)
        .await?
    {
        Some(secret) => secret,
        None => {
            emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
                &receiver,
                "receiver_secret_lookup",
                AuditOutcome::Denied,
                Some("active_secret_missing"),
                body.len(),
                headers.get("idempotency-key").is_some(),
            ))
            .await;
            return Err(incoming_webhook_receiver_not_found());
        }
    };
    if let Err(err) = verify_incoming_signature(
        &headers,
        &receiver.signature_header,
        &secret,
        &body,
        Some(&uri),
    ) {
        emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
            &receiver,
            "receiver_signature_verify",
            AuditOutcome::Denied,
            Some(incoming_webhook_signature_error_reason(&err)),
            body.len(),
            headers.get("idempotency-key").is_some(),
        ))
        .await;
        return Err(err);
    }
    emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
        &receiver,
        "receiver_signature_verify",
        AuditOutcome::Success,
        Some("signature_valid"),
        body.len(),
        headers.get("idempotency-key").is_some(),
    ))
    .await;

    // Idempotency-Key dedupe (#822): opt-in via header. A repeat of the same
    // key + body replays the cached accepted response without re-processing
    // (no duplicate outbox row); the same key with a different body is a 409.
    // Checked after signature verification so unsigned requests cannot read or
    // poison the cache.
    let idempotency_key = headers
        .get("idempotency-key")
        .and_then(|v| v.to_str().ok())
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty());
    let body_hash = {
        use sha2::{Digest, Sha256};
        hex::encode(Sha256::digest(&body))
    };
    if let Some(ref key) = idempotency_key {
        if let Some(cached) = state.idempotency_store.get(&receiver.slug, key).await {
            if cached.body_hash == body_hash {
                emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
                    &receiver,
                    "receiver_idempotency",
                    AuditOutcome::Success,
                    Some("idempotency_replay"),
                    body.len(),
                    true,
                ))
                .await;
                let status = StatusCode::from_u16(cached.response_status).unwrap_or(StatusCode::OK);
                let mut response_body = cached.response_body;
                if let serde_json::Value::Object(ref mut map) = response_body {
                    map.insert("idempotency_replay".to_string(), serde_json::json!(true));
                }
                return Ok((status, Json(response_body)).into_response());
            }
            emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
                &receiver,
                "receiver_idempotency",
                AuditOutcome::Denied,
                Some("idempotency_conflict"),
                body.len(),
                true,
            ))
            .await;
            return Err(incoming_webhook_idempotency_conflict());
        }
    }

    let payload = match incoming_payload_from_body(
        &receiver.schema_ref,
        headers.get(header::CONTENT_TYPE),
        &body,
    ) {
        Ok(payload) => payload,
        Err(err) => {
            emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
                &receiver,
                "receiver_payload_parse",
                AuditOutcome::Failure,
                Some("payload_parse_failed"),
                body.len(),
                idempotency_key.is_some(),
            ))
            .await;
            return Err(err);
        }
    };
    let validation = matric_db::validate_incoming_webhook_payload(
        &receiver.schema_ref,
        receiver.schema_doc.as_ref(),
        &payload,
    )?;
    if !validation.valid {
        emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
            &receiver,
            "receiver_schema_validation",
            AuditOutcome::Denied,
            Some("schema_validation_failed"),
            body.len(),
            idempotency_key.is_some(),
        ))
        .await;
        return Err(incoming_webhook_schema_validation_failed());
    }

    let side_effect =
        apply_incoming_webhook_side_effect(&state, &receiver.schema_ref, &body).await?;

    // Durably capture every accepted incoming webhook into the shared event
    // outbox so the event bus can fan it out (#818). This is in addition to any
    // schema-specific side effect (e.g. Twilio call_event rows) — the generic
    // capture provides a uniform audit/event-bus record for all providers.
    let outbox_event = matric_db::CreateOutboxEvent::new(
        "incoming_webhook.received",
        "incoming_webhook",
        receiver.id,
        serde_json::json!({
            "slug": receiver.slug,
            "provider": receiver.provider,
            "schema_ref": receiver.schema_ref,
            "payload": payload,
            "side_effect": side_effect,
        }),
        None,
    );
    if let Err(e) = state.db.outbox.emit_event(outbox_event).await {
        // Outbox capture failure must not lose the accepted webhook for the
        // caller — the side effect already applied. Log and continue; the
        // caller still receives a metadata-only 200 acknowledgement.
        tracing::warn!(
            error_len = telemetry_text_len(&e.to_string()),
            detail = API_WEBHOOK_DIAGNOSTIC_FAILURE_DETAIL,
            slug_len = telemetry_text_len(&receiver.slug),
            operation = "emit_incoming_webhook_outbox_event",
            "Failed to capture incoming webhook into event outbox"
        );
    }

    let response = incoming_webhook_accepted_response(
        &receiver,
        &payload,
        &side_effect,
        false,
        idempotency_key.is_some(),
    );

    // Cache the accepted outcome for replay within the idempotency window.
    if let Some(ref key) = idempotency_key {
        state
            .idempotency_store
            .store(
                &receiver.slug,
                key,
                &matric_api::services::IdempotencyRecord {
                    body_hash,
                    response_status: StatusCode::OK.as_u16(),
                    response_body: response.clone(),
                },
            )
            .await;
    }

    emit_incoming_webhook_audit_event(incoming_webhook_decision_audit_event(
        &receiver,
        "receiver_accept",
        AuditOutcome::Success,
        Some("accepted"),
        body.len(),
        idempotency_key.is_some(),
    ))
    .await;

    Ok(Json(response).into_response())
}

