async fn emit_twilio_call_event_outbox(
    state: &AppState,
    call_id: Uuid,
    provider_call_id: &str,
    event: matric_api::realtime::adapters::twilio::TwilioCallEventOutbox,
) -> Result<(), ApiError> {
    state
        .db
        .outbox
        .emit_event(matric_db::CreateOutboxEvent::new(
            "call_event",
            "call_session",
            call_id,
            serde_json::json!({
                "call_id": call_id,
                "provider": matric_api::realtime::adapters::twilio::provider_name(),
                "provider_call_id": provider_call_id,
                "event_type": event.event_type,
                "payload": event.payload,
            }),
            None,
        ))
        .await?;
    Ok(())
}

fn twilio_recording_provider_failure(
    context: &'static str,
    error: impl std::fmt::Display,
) -> ApiError {
    let diagnostic = error.to_string();
    ApiError::ProviderFailure {
        capability: "Twilio recording",
        detail: format!("{context}; error_len={}", diagnostic.len()),
    }
}

async fn queue_twilio_recording_transcription(
    state: &AppState,
    session: &matric_core::CallSession,
    recording_url: &str,
) -> Result<Option<Uuid>, ApiError> {
    let file_storage = match state.db.file_storage.as_ref() {
        Some(file_storage) => file_storage,
        None => return Ok(None),
    };

    let response = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(30))
        .build()
        .map_err(|err| twilio_recording_provider_failure("build HTTP client", err))?
        .get(recording_url)
        .send()
        .await
        .map_err(|err| twilio_recording_provider_failure("download recording", err))?;

    if !response.status().is_success() {
        return Err(twilio_recording_provider_failure(
            "download recording",
            format!("status={}", response.status().as_u16()),
        ));
    }

    let content_type = response
        .headers()
        .get(reqwest::header::CONTENT_TYPE)
        .and_then(|value| value.to_str().ok())
        .unwrap_or("audio/wav")
        .split(';')
        .next()
        .unwrap_or("audio/wav")
        .trim()
        .to_string();
    let audio_bytes = response
        .bytes()
        .await
        .map_err(|err| twilio_recording_provider_failure("read recording body", err))?;
    if audio_bytes.is_empty() {
        return Err(ApiError::BadRequest(
            "recording download was empty".to_string(),
        ));
    }

    let note_id = state
        .db
        .notes
        .insert(CreateNoteRequest {
            title: Some(format!("Call recording {}", session.provider_call_id)),
            content: format!(
                "Call recording imported from {} for provider call {}.",
                session.provider, session.provider_call_id
            ),
            format: "markdown".to_string(),
            source: "realtime_call_recording".to_string(),
            collection_id: session.archive_id,
            tags: Some(vec!["call-recording".to_string(), session.provider.clone()]),
            metadata: Some(serde_json::json!({
                "call_id": session.call_id,
                "provider": session.provider,
                "provider_call_id": session.provider_call_id,
                "recording_url": recording_url,
                "batch_transcript_policy": "append_attachment_transcript",
            })),
            document_type_id: None,
        })
        .await?;

    let filename = recording_filename(&session.provider_call_id, &content_type);
    let attachment = {
        let mut tx = state
            .db
            .pool()
            .begin()
            .await
            .map_err(matric_core::Error::Database)?;
        let attachment = file_storage
            .store_file_tx(&mut tx, note_id, &filename, &content_type, &audio_bytes)
            .await?;
        tx.commit().await.map_err(matric_core::Error::Database)?;
        attachment
    };

    let payload = serde_json::json!({
        "parent_attachment_id": attachment.id.to_string(),
        "audio_attachment_id": attachment.id.to_string(),
        "is_video": false,
        "call_id": session.call_id.to_string(),
        "provider": session.provider,
        "provider_call_id": session.provider_call_id,
        "recording_url": recording_url,
        "batch_transcript_policy": "append_attachment_transcript",
    });
    let job_id = state
        .db
        .jobs
        .queue_deduplicated(
            Some(note_id),
            JobType::AudioTranscription,
            JobType::AudioTranscription.default_priority(),
            Some(payload),
            JobType::AudioTranscription.default_cost_tier(),
        )
        .await?;

    let mut metadata = session.metadata.clone();
    if !metadata.is_object() {
        metadata = serde_json::json!({});
    }
    if let Some(obj) = metadata.as_object_mut() {
        obj.insert(
            "batch_transcription".to_string(),
            serde_json::json!({
                "policy": "append_attachment_transcript",
                "note_id": note_id,
                "audio_attachment_id": attachment.id,
                "job_id": job_id,
                "recording_url": recording_url,
            }),
        );
    }
    let _ = state
        .db
        .call_sessions
        .update_session(
            session.call_id,
            matric_core::UpdateCallSessionRequest {
                metadata: Some(metadata),
                ..matric_core::UpdateCallSessionRequest::default()
            },
        )
        .await?;

    if let Some(job_id) = job_id {
        state.event_bus.emit(ServerEvent::JobQueued {
            job_id,
            job_type: format!("{:?}", JobType::AudioTranscription),
            note_id: Some(note_id),
        });
    }

    Ok(job_id)
}

fn recording_filename(provider_call_id: &str, content_type: &str) -> String {
    let extension = match content_type {
        "audio/mpeg" => "mp3",
        "audio/mp4" | "audio/m4a" => "m4a",
        "audio/ogg" => "ogg",
        "audio/webm" => "webm",
        "audio/x-wav" | "audio/wav" | "audio/wave" => "wav",
        _ => "audio",
    };
    format!("{}-recording.{}", provider_call_id, extension)
}

async fn apply_twilio_voice_webhook(
    state: &AppState,
    raw_body: &[u8],
) -> Result<serde_json::Value, ApiError> {
    let event = matric_api::realtime::adapters::twilio::translate_voice_webhook_form(raw_body)?;
    let provider_call_id = event.provider_call_id.clone();
    match &event.control_event {
        matric_api::realtime::CallControlEvent::CallStarted {
            provider,
            remote_party,
            metadata,
            ..
        } if provider == matric_api::realtime::adapters::twilio::provider_name() => {
            if state.call_recording_require_confirmation
                && !twilio_call_started_consent_confirmed(metadata)
            {
                return Ok(serde_json::json!({
                    "type": "call_session_blocked_consent_required",
                    "provider_call_id": provider_call_id,
                    "disclosure": call_recording_disclosure_config(state.call_recording_require_confirmation),
                }));
            }

            let existing = state
                .db
                .call_sessions
                .get_session_by_provider_call_id(
                    matric_api::realtime::adapters::twilio::provider_name(),
                    &provider_call_id,
                )
                .await?;
            if let Some(session) = existing {
                if let Some(outbox_event) =
                    matric_api::realtime::adapters::twilio::call_event_outbox_for_control_event(
                        &event.control_event,
                        true,
                    )
                {
                    emit_twilio_call_event_outbox(
                        state,
                        session.call_id,
                        &provider_call_id,
                        outbox_event,
                    )
                    .await?;
                }
                return Ok(serde_json::json!({
                    "type": "call_session_existing",
                    "call_id": session.call_id,
                    "provider_call_id": provider_call_id,
                }));
            }

            let session = state
                .db
                .call_sessions
                .create_session(matric_core::CreateCallSessionRequest {
                    provider: matric_api::realtime::adapters::twilio::provider_name().to_string(),
                    provider_call_id: provider_call_id.clone(),
                    started_at: Some(chrono::Utc::now()),
                    asr_backend: Some("deepgram".to_string()),
                    remote_party: remote_party.clone(),
                    archive_id: None,
                    metadata: serde_json::json!({
                        "source": "twilio_voice_webhook",
                        "call_started_metadata": metadata,
                        "recording_disclosure": call_recording_disclosure_config(state.call_recording_require_confirmation),
                        "consent_confirmed": twilio_call_started_consent_confirmed(metadata),
                    }),
                })
                .await?;
            if let Some(outbox_event) =
                matric_api::realtime::adapters::twilio::call_event_outbox_for_control_event(
                    &event.control_event,
                    false,
                )
            {
                emit_twilio_call_event_outbox(
                    state,
                    session.call_id,
                    &provider_call_id,
                    outbox_event,
                )
                .await?;
            }
            Ok(serde_json::json!({
                "type": "call_session_created",
                "call_id": session.call_id,
                "provider_call_id": provider_call_id,
            }))
        }
        matric_api::realtime::CallControlEvent::StateChanged {
            state: matric_api::realtime::CallState::Active,
        } => {
            if let Some(session) = state
                .db
                .call_sessions
                .get_session_by_provider_call_id(
                    matric_api::realtime::adapters::twilio::provider_name(),
                    &provider_call_id,
                )
                .await?
            {
                if let Some(outbox_event) =
                    matric_api::realtime::adapters::twilio::call_event_outbox_for_control_event(
                        &event.control_event,
                        false,
                    )
                {
                    emit_twilio_call_event_outbox(
                        state,
                        session.call_id,
                        &provider_call_id,
                        outbox_event,
                    )
                    .await?;
                }
                return Ok(serde_json::json!({
                    "type": "call_session_active",
                    "call_id": session.call_id,
                    "provider_call_id": provider_call_id,
                }));
            }
            Ok(serde_json::json!({
                "type": "call_session_missing",
                "provider_call_id": provider_call_id,
            }))
        }
        matric_api::realtime::CallControlEvent::StateChanged {
            state: matric_api::realtime::CallState::Ended { reason },
        } => {
            if let Some(session) = state
                .db
                .call_sessions
                .get_session_by_provider_call_id(
                    matric_api::realtime::adapters::twilio::provider_name(),
                    &provider_call_id,
                )
                .await?
            {
                let ended = state
                    .db
                    .call_sessions
                    .end_session(
                        session.call_id,
                        matric_api::realtime::adapters::twilio::end_reason_label(reason),
                    )
                    .await?;
                if let Some(ended_session) = ended.as_ref() {
                    if let Some(outbox_event) =
                        matric_api::realtime::adapters::twilio::call_event_outbox_for_control_event(
                            &event.control_event,
                            false,
                        )
                    {
                        emit_twilio_call_event_outbox(
                            state,
                            ended_session.call_id,
                            &provider_call_id,
                            outbox_event,
                        )
                        .await?;
                    }
                }
                return Ok(serde_json::json!({
                    "type": "call_session_ended",
                    "call_id": ended.map(|session| session.call_id),
                    "provider_call_id": provider_call_id,
                }));
            }
            Ok(serde_json::json!({
                "type": "call_session_missing",
                "provider_call_id": provider_call_id,
            }))
        }
        matric_api::realtime::CallControlEvent::RecordingAvailable { url } => {
            let session = state
                .db
                .call_sessions
                .get_session_by_provider_call_id(
                    matric_api::realtime::adapters::twilio::provider_name(),
                    &provider_call_id,
                )
                .await?;
            let mut transcription_job_id = None;
            if let Some(session) = session.as_ref() {
                if let Some(outbox_event) =
                    matric_api::realtime::adapters::twilio::call_event_outbox_for_control_event(
                        &event.control_event,
                        false,
                    )
                {
                    emit_twilio_call_event_outbox(
                        state,
                        session.call_id,
                        &provider_call_id,
                        outbox_event,
                    )
                    .await?;
                }
                transcription_job_id =
                    queue_twilio_recording_transcription(state, session, url).await?;
            }
            Ok(serde_json::json!({
                "type": "recording_available",
                "call_id": session.map(|session| session.call_id),
                "provider_call_id": provider_call_id,
                "url": url,
                "audio_transcription_job_id": transcription_job_id,
            }))
        }
        other => Ok(serde_json::json!({
            "type": "control_event_observed",
            "provider_call_id": provider_call_id,
            "event": format!("{:?}", other),
        })),
    }
}

#[utoipa::path(post, path = "/api/v1/webhooks/incoming/validate", tag = "Incoming Webhooks",
    request_body = matric_core::ValidateIncomingWebhookPayloadRequest,
    responses((status = 200, description = "Validation result")))]
async fn validate_incoming_webhook_payload_handler(
    Json(body): Json<matric_core::ValidateIncomingWebhookPayloadRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let response =
        matric_db::validate_incoming_webhook_payload(&body.schema_ref, None, &body.payload)?;
    let status = if response.valid {
        StatusCode::OK
    } else {
        StatusCode::UNPROCESSABLE_ENTITY
    };
    Ok((status, Json(response)))
}

// =============================================================================
// RATE LIMITING MIDDLEWARE
// =============================================================================

async fn rate_limit_middleware(
    State(state): State<AppState>,
    request: axum::extract::Request,
    next: axum::middleware::Next,
) -> axum::response::Response {
    // If rate limiting is disabled, pass through
    if let Some(limiter) = &state.rate_limiter {
        // Check rate limit
        if limiter.check().is_err() {
            tracing::warn!("Rate limit exceeded");
            return problem_response(
                StatusCode::TOO_MANY_REQUESTS,
                ProblemType::RateLimit,
                "Too many requests. Please wait before retrying.".to_string(),
                None,
            );
        }
    }
    next.run(request).await
}

// =============================================================================
// CACHE CONTROL MIDDLEWARE (fixes #211)
// =============================================================================

/// Sets HTTP Cache-Control and ETag headers based on request method and path.
///
/// Cache-Control policy:
/// - Mutation requests (POST/PUT/PATCH/DELETE): `no-store`
/// - Stable reference data (document-types, concepts/schemes): `public, max-age=300`
/// - Single-resource GETs with ID: `private, no-cache` (allows conditional caching)
/// - List/search endpoints: `private, no-cache`
/// - Health endpoints: `no-cache, max-age=0`
///
/// ETag support:
/// - GET responses on /api/v1/ get a weak ETag derived from response body hash
/// - If-None-Match requests return 304 Not Modified when ETag matches
async fn cache_control_middleware(
    request: axum::extract::Request,
    next: axum::middleware::Next,
) -> axum::response::Response {
    let method = request.method().clone();
    let path = request.uri().path().to_string();
    let if_none_match = request
        .headers()
        .get(header::IF_NONE_MATCH)
        .and_then(|v| v.to_str().ok())
        .map(|s| s.to_string());

    let mut response = next.run(request).await;

    // Skip if handler already set Cache-Control
    if response.headers().contains_key(header::CACHE_CONTROL) {
        return response;
    }

    let is_get = method == Method::GET || method == Method::HEAD;

    let cache_value = if !is_get {
        // Mutations must never be cached
        "no-store"
    } else if path.starts_with("/api/v1/document-types")
        || path.starts_with("/api/v1/concepts/schemes")
    {
        // Stable reference data — cache for 5 minutes
        "public, max-age=300"
    } else if path.starts_with("/health") || path.starts_with("/api/v1/health") {
        // Health checks — always fresh
        "no-cache, max-age=0"
    } else if path.starts_with("/api/v1/") {
        // All other API GETs — allow private caching with revalidation
        "private, no-cache"
    } else {
        // Static assets (docs, openapi.yaml)
        "public, max-age=3600"
    };

    response
        .headers_mut()
        .insert(header::CACHE_CONTROL, cache_value.parse().unwrap());

    // Responses vary by archive selection header
    if path.starts_with("/api/v1/") {
        response
            .headers_mut()
            .append(header::VARY, "X-Fortemi-Memory".parse().unwrap());
    }

    // ETag support for successful GET responses on API paths.
    // Skip for file downloads (streaming bodies) — collecting the body into memory
    // would either OOM or, when it exceeds the 2MB limit, destroy the stream.
    let is_download = path.ends_with("/download")
        || response
            .headers()
            .get(header::ACCEPT_RANGES)
            .and_then(|v| v.to_str().ok())
            .is_some_and(|v| v == "bytes");

    if is_get && path.starts_with("/api/v1/") && response.status().is_success() && !is_download {
        // Collect body bytes to compute hash (safe — non-download API responses are small)
        let (parts, body) = response.into_parts();
        if let Ok(bytes) = axum::body::to_bytes(body, 2 * 1024 * 1024).await {
            // Compute weak ETag from FNV-1a hash of body
            let hash = bytes.iter().fold(0xcbf29ce484222325u64, |h, &b| {
                (h ^ b as u64).wrapping_mul(0x100000001b3)
            });
            let etag = format!("W/\"{:x}\"", hash);

            // Check If-None-Match
            if let Some(client_etag) = if_none_match {
                if client_etag.contains(&etag) || client_etag.trim() == etag {
                    let mut not_modified = axum::response::Response::new(Body::empty());
                    *not_modified.status_mut() = StatusCode::NOT_MODIFIED;
                    not_modified
                        .headers_mut()
                        .insert(header::ETAG, etag.parse().unwrap());
                    // Preserve cache headers
                    for (k, v) in parts.headers.iter() {
                        if k == header::CACHE_CONTROL || k == header::VARY {
                            not_modified.headers_mut().insert(k.clone(), v.clone());
                        }
                    }
                    return not_modified;
                }
            }

            let mut response = axum::response::Response::from_parts(parts, Body::from(bytes));
            response
                .headers_mut()
                .insert(header::ETAG, etag.parse().unwrap());
            return response;
        }
        // Body exceeded 2MB limit — should not happen for non-download API responses.
        // Return without ETag rather than losing the response body.
        axum::response::Response::from_parts(parts, Body::empty())
    } else {
        response
    }
}

// =============================================================================
// PROBLEM DETAILS REQUEST-ID MIDDLEWARE (#967)
// =============================================================================

async fn problem_request_id_middleware(
    request: axum::extract::Request,
    next: axum::middleware::Next,
) -> axum::response::Response {
    inject_request_id_into_problem_response(next.run(request).await).await
}

async fn inject_request_id_into_problem_response(
    response: axum::response::Response,
) -> axum::response::Response {
    if !is_problem_details_response(&response) {
        return response;
    }

    let Some(request_id) = response
        .headers()
        .get("x-request-id")
        .and_then(|value| value.to_str().ok())
        .map(str::to_string)
    else {
        return response;
    };

    let (mut parts, body) = response.into_parts();
    let Ok(bytes) = axum::body::to_bytes(body, 1024 * 1024).await else {
        return axum::response::Response::from_parts(parts, Body::empty());
    };

    let mut problem = match serde_json::from_slice::<serde_json::Value>(&bytes) {
        Ok(problem) => problem,
        Err(_) => return axum::response::Response::from_parts(parts, Body::from(bytes)),
    };

    if let Some(object) = problem.as_object_mut() {
        object
            .entry("request_id")
            .or_insert_with(|| serde_json::Value::String(request_id));
    }

    let Ok(updated) = serde_json::to_vec(&problem) else {
        return axum::response::Response::from_parts(parts, Body::from(bytes));
    };

    parts.headers.remove(header::CONTENT_LENGTH);
    axum::response::Response::from_parts(parts, Body::from(updated))
}

fn is_problem_details_response(response: &axum::response::Response) -> bool {
    response
        .headers()
        .get(header::CONTENT_TYPE)
        .and_then(|value| value.to_str().ok())
        .is_some_and(|content_type| content_type.starts_with("application/problem+json"))
}

// =============================================================================
// SECURITY RESPONSE HEADERS (#967)
// =============================================================================

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum SecurityHeaderClass {
    ApiJson,
    BrowserDocument,
    DownloadOrMedia,
    PublicProbe,
}

async fn security_headers_middleware(
    request: axum::extract::Request,
    next: axum::middleware::Next,
) -> axum::response::Response {
    let path = request.uri().path().to_string();
    let mut response = next.run(request).await;
    apply_security_headers(&path, &mut response);
    response
}

fn apply_security_headers(path: &str, response: &mut axum::response::Response) {
    let header_class = security_header_class(path, response);
    let is_error = response.status().is_client_error() || response.status().is_server_error();
    let headers = response.headers_mut();

    headers
        .entry("x-content-type-options")
        .or_insert_with(|| HeaderValue::from_static("nosniff"));
    headers
        .entry("referrer-policy")
        .or_insert_with(|| HeaderValue::from_static("no-referrer"));
    headers.entry("permissions-policy").or_insert_with(|| {
        HeaderValue::from_static("camera=(), microphone=(), geolocation=(), payment=(), usb=()")
    });

    match header_class {
        SecurityHeaderClass::BrowserDocument => {
            headers.entry("content-security-policy").or_insert_with(|| {
                HeaderValue::from_static("default-src 'self'; frame-ancestors 'none'")
            });
            headers
                .entry("x-frame-options")
                .or_insert_with(|| HeaderValue::from_static("DENY"));
            headers
                .entry("cross-origin-opener-policy")
                .or_insert_with(|| HeaderValue::from_static("same-origin"));
            headers
                .entry("cross-origin-resource-policy")
                .or_insert_with(|| HeaderValue::from_static("same-origin"));
        }
        SecurityHeaderClass::ApiJson | SecurityHeaderClass::PublicProbe => {
            headers.entry("content-security-policy").or_insert_with(|| {
                HeaderValue::from_static("default-src 'none'; frame-ancestors 'none'")
            });
            headers
                .entry("x-frame-options")
                .or_insert_with(|| HeaderValue::from_static("DENY"));
            headers
                .entry("cross-origin-opener-policy")
                .or_insert_with(|| HeaderValue::from_static("same-origin"));
        }
        SecurityHeaderClass::DownloadOrMedia => {
            headers
                .entry("cross-origin-resource-policy")
                .or_insert_with(|| HeaderValue::from_static("same-origin"));
        }
    }

    if is_error {
        headers.insert(header::CACHE_CONTROL, HeaderValue::from_static("no-store"));
    }
}

fn security_header_class(path: &str, response: &axum::response::Response) -> SecurityHeaderClass {
    if path == "/health" || path.starts_with("/api/v1/health") {
        return SecurityHeaderClass::PublicProbe;
    }
    if path.starts_with("/docs")
        || path.starts_with("/swagger")
        || path.starts_with("/oauth")
        || path.ends_with(".html")
    {
        return SecurityHeaderClass::BrowserDocument;
    }
    if is_download_or_media_response(path, response) {
        return SecurityHeaderClass::DownloadOrMedia;
    }
    SecurityHeaderClass::ApiJson
}

fn is_download_or_media_response(path: &str, response: &axum::response::Response) -> bool {
    if path.ends_with("/download")
        || response.headers().contains_key(header::CONTENT_DISPOSITION)
        || response.headers().contains_key(header::ACCEPT_RANGES)
    {
        return true;
    }

    response
        .headers()
        .get(header::CONTENT_TYPE)
        .and_then(|value| value.to_str().ok())
        .is_some_and(|content_type| {
            content_type.starts_with("audio/")
                || content_type.starts_with("video/")
                || content_type.starts_with("image/")
                || content_type == "text/vtt"
        })
}

// =============================================================================
// AUTHENTICATION MIDDLEWARE
// =============================================================================

/// Authentication middleware.
///
/// Always validates Bearer tokens when present, regardless of `REQUIRE_AUTH`.
/// This ensures policy evaluation works for authenticated requests even when
/// anonymous access is allowed.
///
/// Behavior:
/// - Public routes: bypass all auth (health, oauth, docs, SSE/WS)
/// - Bearer token present + valid: inject Auth with principal scope for policy evaluation
/// - Bearer token present + invalid: always reject with 401
/// - No token + REQUIRE_AUTH=true: reject with 401
/// - No token + REQUIRE_AUTH=false: allow as Anonymous
///
async fn auth_middleware(
    State(state): State<AppState>,
    request: axum::http::Request<axum::body::Body>,
    next: axum::middleware::Next,
) -> axum::response::Response {
    let path = request.uri().path().to_string();
    let method = request.method().clone();

    // Public routes and CORS preflights bypass all auth.
    if is_auth_exempt(&method, &path) {
        return next.run(request).await;
    }

    // Always try to parse Bearer token if present
    let auth_header = request
        .headers()
        .get(header::AUTHORIZATION)
        .and_then(|v| v.to_str().ok())
        .map(|s| s.to_string());

    let has_token = auth_header.is_some();

    let principal = match &auth_header {
        Some(header) if header.starts_with("Bearer ") => {
            let token = header.trim_start_matches("Bearer ").trim();

            if token.starts_with("mm_at_") {
                // OAuth access token
                match state.db.oauth.validate_access_token(token).await {
                    Ok(Some(oauth_token)) => {
                        // Sliding window refresh
                        let lifetime = state.token_lifetime_for_scope(&oauth_token.scope);
                        let _ = state
                            .db
                            .oauth
                            .validate_and_extend_token(token, lifetime)
                            .await;
                        Some(AuthPrincipal::OAuthClient {
                            client_id: oauth_token.client_id,
                            scope: oauth_token.scope,
                            user_id: oauth_token.user_id,
                        })
                    }
                    _ => None,
                }
            } else if token.starts_with("mm_key_") {
                // API key
                match state.db.oauth.validate_api_key(token).await {
                    Ok(Some(api_key)) => Some(AuthPrincipal::ApiKey {
                        key_id: api_key.id,
                        scope: api_key.scope,
                    }),
                    _ => None,
                }
            } else {
                None
            }
        }
        _ => None,
    };

    // Handle authentication result
    match principal {
        Some(p) => {
            // Inject auth info into request extensions
            let mut request = request;
            if let Some(input) = route_policy::authorization_input_for_request(&method, &path, None)
            {
                request.extensions_mut().insert(input);
            }
            request.extensions_mut().insert(Auth { principal: p });
            next.run(request).await
        }
        None if has_token => {
            // Token was present but invalid — always reject
            problem_response(
                StatusCode::UNAUTHORIZED,
                ProblemType::Unauthorized,
                "Invalid or expired bearer token.".to_string(),
                None,
            )
        }
        None => {
            // No token provided
            if state.require_auth {
                problem_response(
                    StatusCode::UNAUTHORIZED,
                    ProblemType::Unauthorized,
                    "Authentication required. Provide a valid Bearer token.".to_string(),
                    None,
                )
            } else {
                // Anonymous access allowed — inject Anonymous principal
                let mut request = request;
                if let Some(input) =
                    route_policy::authorization_input_for_request(&method, &path, None)
                {
                    request.extensions_mut().insert(input);
                }
                request.extensions_mut().insert(Auth {
                    principal: AuthPrincipal::Anonymous,
                });
                next.run(request).await
            }
        }
    }
}

async fn authorize_middleware(
    State(state): State<AppState>,
    request: axum::http::Request<axum::body::Body>,
    next: axum::middleware::Next,
) -> axum::response::Response {
    let Some(auth) = request.extensions().get::<Auth>().cloned() else {
        return next.run(request).await;
    };
    let Some(input) = request
        .extensions()
        .get::<route_policy::RoutePolicyInput>()
        .cloned()
    else {
        return next.run(request).await;
    };

    let archive_ctx = request.extensions().get::<ArchiveContext>().cloned();
    let input =
        normalize_route_policy_input_for_authorization(&state, input, archive_ctx.as_ref()).await;

    match authorize_policy_input(state.authorization_policy.as_ref(), &auth, &input).await {
        Ok(()) => next.run(request).await,
        Err(response) => response,
    }
}

async fn normalize_route_policy_input_for_authorization(
    state: &AppState,
    input: route_policy::RoutePolicyInput,
    archive_ctx: Option<&ArchiveContext>,
) -> route_policy::RoutePolicyInput {
    let input = apply_archive_context_to_policy_input(input, archive_ctx);
    let input =
        normalize_note_route_policy_input(input, |note_id| state.db.notes.exists(note_id)).await;
    let input = normalize_credential_route_policy_input(input, |api_key_id| {
        state.db.oauth.get_api_key(api_key_id)
    })
    .await;
    let input = normalize_attachment_route_policy_input(input, |attachment_id| async move {
        let Some(file_storage) = state.db.file_storage.as_ref() else {
            return Err(matric_core::Error::Config(
                "file storage not configured".to_string(),
            ));
        };

        match file_storage.get(attachment_id).await {
            Ok(attachment) => Ok(Some(attachment.note_id)),
            Err(matric_core::Error::NotFound(_)) => Ok(None),
            Err(err) => Err(err),
        }
    })
    .await;
    let input = normalize_archive_route_policy_input(input, |archive_name| async move {
        state.db.archives.get_archive_by_name(&archive_name).await
    })
    .await;
    let input = normalize_collection_route_policy_input(input, |collection_id| {
        lookup_collection_for_authorization(state, archive_ctx, collection_id)
    })
    .await;
    let input = normalize_template_route_policy_input(input, |template_id| {
        lookup_template_for_authorization(state, archive_ctx, template_id)
    })
    .await;
    let input = normalize_taxonomy_relation_route_policy_input(input, |concept_id| {
        state.db.skos.get_concept(concept_id)
    })
    .await;
    let input = normalize_taxonomy_concept_route_policy_input(input, |concept_id| {
        state.db.skos.get_concept(concept_id)
    })
    .await;
    let input = normalize_taxonomy_scheme_route_policy_input(input, |scheme_id| {
        state.db.skos.get_scheme(scheme_id)
    })
    .await;
    let input = normalize_taxonomy_collection_route_policy_input(input, |collection_id| {
        state.db.skos.get_collection(collection_id)
    })
    .await;
    let input =
        normalize_document_type_route_policy_input(input, |document_type_name| async move {
            state
                .db
                .document_types
                .get_by_name(&document_type_name)
                .await
                .map(|document_type| document_type.map(DocumentTypeResourceMetadata::from))
        })
        .await;
    let input = normalize_job_route_policy_input(input, |job_id| state.db.jobs.get(job_id)).await;
    let input = normalize_webhook_control_route_policy_input(input, |webhook_id| {
        state.db.webhooks.get(webhook_id)
    })
    .await;
    let input = normalize_inbound_source_route_policy_input(input, |source_name| async move {
        state.db.inbound_sources.get_by_name(&source_name).await
    })
    .await;
    normalize_pke_keyset_route_policy_input(input, |name_or_id| async move {
        let keyset = if let Ok(keyset_id) = Uuid::parse_str(&name_or_id) {
            state.db.pke_keysets.get_by_id(keyset_id).await
        } else {
            state.db.pke_keysets.get_by_name(&name_or_id).await
        }?;
        Ok(keyset.map(PkeKeysetResourceMetadata::from))
    })
    .await
}

fn apply_archive_context_to_policy_input(
    mut input: route_policy::RoutePolicyInput,
    archive_ctx: Option<&ArchiveContext>,
) -> route_policy::RoutePolicyInput {
    let Some(archive_ctx) = archive_ctx else {
        return input;
    };

    input.resource.attrs.insert(
        "archive_route_schema".to_string(),
        serde_json::json!(archive_ctx.schema),
    );
    input.resource.attrs.insert(
        "archive_route_is_default".to_string(),
        serde_json::json!(archive_ctx.is_default),
    );
    if let Some(name) = &archive_ctx.name {
        input
            .resource
            .attrs
            .insert("archive_route_name".to_string(), serde_json::json!(name));
    }

    input.context.environment.insert(
        "archive_schema".to_string(),
        serde_json::json!(archive_ctx.schema),
    );
    input.context.environment.insert(
        "archive_is_default".to_string(),
        serde_json::json!(archive_ctx.is_default),
    );
    if let Some(name) = &archive_ctx.name {
        input
            .context
            .environment
            .insert("archive_name".to_string(), serde_json::json!(name));
    }

    input
}

async fn lookup_collection_for_authorization(
    state: &AppState,
    archive_ctx: Option<&ArchiveContext>,
    collection_id: Uuid,
) -> matric_core::Result<Option<matric_core::Collection>> {
    let Some(archive_ctx) = archive_ctx else {
        return state.db.collections.get(collection_id).await;
    };
    if archive_ctx.schema == "public" {
        return state.db.collections.get(collection_id).await;
    }

    let schema_ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = schema_ctx.begin_tx().await?;
    let collection = state.db.collections.get_tx(&mut tx, collection_id).await?;
    tx.commit().await.map_err(matric_core::Error::Database)?;
    Ok(collection)
}

async fn lookup_template_for_authorization(
    state: &AppState,
    archive_ctx: Option<&ArchiveContext>,
    template_id: Uuid,
) -> matric_core::Result<Option<matric_core::NoteTemplate>> {
    let Some(archive_ctx) = archive_ctx else {
        return state.db.templates.get(template_id).await;
    };
    if archive_ctx.schema == "public" {
        return state.db.templates.get(template_id).await;
    }

    let schema_ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = schema_ctx.begin_tx().await?;
    let template = state.db.templates.get_tx(&mut tx, template_id).await?;
    tx.commit().await.map_err(matric_core::Error::Database)?;
    Ok(template)
}

