async fn authorize_policy_input(
    policy: &dyn AuthorizationPolicy,
    auth: &Auth,
    input: &route_policy::RoutePolicyInput,
) -> Result<(), axum::response::Response> {
    if hosted_policy_requires_normalized_resource(policy, input) {
        emit_auth_decision_audit_event(auth_decision_audit_event(
            auth,
            input,
            AuditOutcome::Denied,
            Some(DenyReason::InvalidResource),
            policy.policy_id(),
            policy.policy_version(),
        ))
        .await;
        tracing::warn!("authorization denied: resource requires backing-store normalization");
        return Err(problem_response(
            StatusCode::FORBIDDEN,
            ProblemType::Forbidden,
            "Authorization denied.".to_string(),
            None,
        ));
    }

    match policy
        .authorize(
            &auth.principal,
            &input.action,
            &input.resource,
            &input.context,
        )
        .await
    {
        Ok(Decision::Allow {
            policy_id,
            policy_version,
            ..
        }) => {
            emit_auth_decision_audit_event(auth_decision_audit_event(
                auth,
                input,
                AuditOutcome::Success,
                None,
                &policy_id,
                &policy_version,
            ))
            .await;
            Ok(())
        }
        Ok(
            Decision::Deny {
                reason,
                policy_id,
                policy_version,
            }
            | Decision::Indeterminate {
                reason,
                policy_id,
                policy_version,
            },
        ) => {
            emit_auth_decision_audit_event(auth_decision_audit_event(
                auth,
                input,
                AuditOutcome::Denied,
                Some(reason.clone()),
                &policy_id,
                &policy_version,
            ))
            .await;
            tracing::warn!(reason = ?reason, "authorization denied");
            Err(problem_response(
                StatusCode::FORBIDDEN,
                ProblemType::Forbidden,
                "Authorization denied.".to_string(),
                None,
            ))
        }
        Err(err) => {
            emit_auth_decision_audit_event(auth_decision_audit_event(
                auth,
                input,
                AuditOutcome::Error,
                None,
                policy.policy_id(),
                policy.policy_version(),
            ))
            .await;
            error!(
                error_len = telemetry_text_len(&err.to_string()),
                detail = API_AUTHZ_POLICY_DIAGNOSTIC_FAILURE_DETAIL,
                operation = "authorize_policy_input",
                "authorization policy error"
            );
            Err(problem_response(
                StatusCode::FORBIDDEN,
                ProblemType::Forbidden,
                "Authorization policy error.".to_string(),
                None,
            ))
        }
    }
}

fn hosted_policy_requires_normalized_resource(
    policy: &dyn AuthorizationPolicy,
    input: &route_policy::RoutePolicyInput,
) -> bool {
    policy.policy_id() == "role_based"
        && input
            .resource
            .attrs
            .get("requires_backing_resource_normalization")
            .and_then(|value| value.as_bool())
            .unwrap_or(false)
        && !input
            .resource
            .attrs
            .get("resource_id_normalized")
            .and_then(|value| value.as_bool())
            .unwrap_or(false)
}

async fn emit_auth_decision_audit_event(event: AuditEvent) {
    if let Err(err) = TracingSink.emit(event).await {
        warn!(
            error_len = telemetry_text_len(&err.to_string()),
            detail = API_AUDIT_EMIT_DIAGNOSTIC_FAILURE_DETAIL,
            operation = "emit_auth_decision_audit_event",
            "failed to emit authorization decision audit event"
        );
    }
}

fn auth_decision_audit_event(
    auth: &Auth,
    input: &route_policy::RoutePolicyInput,
    outcome: AuditOutcome,
    reason: Option<DenyReason>,
    policy_id: &str,
    policy_version: &str,
) -> AuditEvent {
    let action_name = if outcome == AuditOutcome::Denied {
        "decision_deny"
    } else {
        "decision"
    };
    let mut event = AuditEvent::new("auth", action_name, outcome)
        .with_principal(auth_principal_audit_id(&auth.principal))
        .with_attr("policy_id", policy_id.to_string())
        .with_attr("policy_version", policy_version.to_string())
        .with_attr("action_name", input.action.name.clone())
        .with_attr("scope_family", format!("{:?}", input.action.scope_family))
        .with_attr("route_template", input.policy.path.to_string())
        .with_attr("policy_class", format!("{:?}", input.policy.class))
        .with_attr("resource_kind", format!("{:?}", input.resource.kind));

    if let Some(tenant_id) = input
        .resource
        .tenant_id
        .clone()
        .or_else(|| input.context.tenant_id.clone())
    {
        event = event.with_tenant(tenant_id);
    }
    event.resource_kind = Some(format!("{:?}", input.resource.kind));
    event.resource_id = input.resource.id.clone();
    if let Some(reason) = reason {
        event.reason = Some(format!("{reason:?}"));
        event = event.with_attr("reason_code", format!("{reason:?}"));
    }
    if let Some(value) = input.resource.attrs.get("resource_id_normalized") {
        event = event.with_attr("resource_id_normalized", value.clone());
    }
    if let Some(value) = input
        .resource
        .attrs
        .get("requires_backing_resource_normalization")
    {
        event = event.with_attr("requires_backing_resource_normalization", value.clone());
    }
    event.source = AuditSource::Api;
    event.visibility = AuditVisibilityClass::SecurityRestricted;
    event.severity = match outcome {
        AuditOutcome::Success => AuditSeverity::Info,
        AuditOutcome::Denied => AuditSeverity::Warn,
        AuditOutcome::Error | AuditOutcome::Failure => AuditSeverity::Error,
        AuditOutcome::Unknown => AuditSeverity::Warn,
    };
    event.failure_policy = AuditFailurePolicy::BestEffort;
    event.sanitized()
}

fn auth_principal_audit_id(principal: &AuthPrincipal) -> String {
    match principal {
        AuthPrincipal::OAuthClient {
            client_id, user_id, ..
        } => user_id
            .as_ref()
            .map(|user_id| format!("oauth_user:{user_id}"))
            .unwrap_or_else(|| format!("oauth_client:{client_id}")),
        AuthPrincipal::ApiKey { key_id, .. } => format!("api_key:{key_id}"),
        AuthPrincipal::Anonymous => "anonymous".to_string(),
    }
}

/// Check if a request is exempt from authentication.
fn is_auth_exempt(method: &axum::http::Method, path: &str) -> bool {
    method == axum::http::Method::OPTIONS
        || is_public_route(path)
        || is_public_incoming_webhook_route(method, path)
}

/// Check if a route is public (accessible without authentication).
fn is_public_route(path: &str) -> bool {
    route_policy::is_public_without_bearer(path)
}

/// Incoming webhook receive requests are authenticated by their provider HMAC
/// signature, not by a Fortemi bearer token. Keep this method-aware because the
/// same slug path also hosts bearer-protected receiver management methods.
fn is_public_incoming_webhook_route(method: &axum::http::Method, path: &str) -> bool {
    if method != axum::http::Method::POST {
        return false;
    }

    if path == "/api/v1/webhooks/incoming/validate" {
        return true;
    }

    let Some(slug) = path.strip_prefix("/api/v1/webhooks/incoming/") else {
        return false;
    };

    !slug.is_empty() && !slug.contains('/')
}

/// Get rate limiting status.
#[utoipa::path(get, path = "/api/v1/rate-limit/status", tag = "System",
    responses((status = 200, description = "Success")))]
async fn rate_limit_status(State(state): State<AppState>) -> impl IntoResponse {
    if let Some(_limiter) = &state.rate_limiter {
        Json(serde_json::json!({
            "enabled": true,
            "message": "Rate limiting is active"
        }))
    } else {
        Json(serde_json::json!({
            "enabled": false,
            "message": "Rate limiting is disabled"
        }))
    }
}

// =============================================================================
// HEALTH CHECK
// =============================================================================

fn health_dependency_error_code(kind: &str) -> &'static str {
    match kind {
        "database_query" => "database_query_failed",
        "dependency_timeout" => "dependency_timeout",
        "cache_unavailable" => "cache_unavailable",
        "provider_unreachable" => "provider_unreachable",
        "provider_check" => "provider_check_failed",
        "provider_unhealthy" => "provider_unhealthy",
        "backend_not_initialized" => "backend_not_initialized",
        _ => "dependency_check_failed",
    }
}

fn set_health_service_reason_code(
    services: &mut serde_json::Value,
    service_name: &str,
    reason_code: &str,
) {
    services[service_name]["reason_code"] = serde_json::Value::String(reason_code.to_string());
}

fn provider_url_configured(url: &str) -> bool {
    !url.trim().is_empty()
}

#[utoipa::path(
    get,
    path = "/health",
    tag = "System",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn health_check(State(state): State<AppState>) -> impl IntoResponse {
    let job_processing = if let Some(ref ps) = state.pause_state {
        if ps.is_globally_paused() {
            "paused"
        } else {
            "running"
        }
    } else {
        "running"
    };

    // Build inference status for health response (#568, #630).
    // `configured` reflects static env/db config; `available` reflects the latest
    // periodic reachability probe (#630) so transient provider outages don't latch
    // chat to "offline" for the Fortemi process lifetime.
    let gen_backend = state.generation_backend();
    let inference_reachable = state.inference_available.load(Ordering::Relaxed);
    let inference_info = match &gen_backend {
        Some(backend) => serde_json::json!({
            "configured": true,
            "available": inference_reachable,
            "provider_url_configured": provider_url_configured(backend.base_url()),
            "gen_model": GenerationBackend::model_name(backend.as_ref()),
            "embed_model": EmbeddingBackend::model_name(backend.as_ref()),
        }),
        None => serde_json::json!({
            "configured": false,
            "available": false,
        }),
    };

    Json(serde_json::json!({
        "status": "healthy",
        "version": env!("CARGO_PKG_VERSION"),
        "git_sha": state.git_sha,
        "build_date": state.build_date,
        "capabilities": {
            "inference": inference_info,
            "vision": state.vision_backend.is_some(),
            "audio_transcription": state.transcription_backend.is_some(),
            "speaker_diarization": state.diarization_backend.is_some(),
            "ner": state.ner_backend.is_some(),
            "auth_required": state.require_auth,
            "extraction_strategies": state.extraction_strategies,
            "chat": {
                "available": gen_backend.is_some() && inference_reachable,
                "configured": gen_backend.is_some(),
                "max_concurrent": matric_core::defaults::chat_max_concurrent(),
            },
        },
        "job_processing": job_processing,
        "sse": state.event_bus.metrics.snapshot(),
    }))
}

#[utoipa::path(
    get,
    path = "/api/v1/health/streaming",
    tag = "System",
    responses((status = 200, description = "Streaming subsystem health and realtime metrics"))
)]
async fn streaming_health_check(
    State(state): State<AppState>,
) -> Result<impl IntoResponse, ApiError> {
    let call_metrics = state.db.call_sessions.realtime_metrics().await?;
    let deepgram_rate = realtime_asr_deepgram_cost_per_minute();
    let deepgram_metrics = state
        .realtime_deepgram_metrics
        .as_ref()
        .map(|metrics| metrics.snapshot());

    Ok(Json(serde_json::json!({
        "status": "healthy",
        "sse": state.event_bus.metrics.snapshot(),
        "rtp": build_rtp_metrics(call_metrics, deepgram_rate, deepgram_metrics),
        "chat": state.chat_stream_metrics.snapshot(),
        "ingest": state.ingest_stream_metrics.snapshot(),
        "inbound": state.inbound_metrics.public_snapshot(),
    })))
}

fn realtime_asr_backend_from_env() -> (
    Option<Arc<dyn matric_api::realtime::asr::StreamingASRBackend>>,
    Option<Arc<matric_api::realtime::asr::deepgram::DeepgramMetrics>>,
) {
    match std::env::var("REALTIME_ASR_BACKEND")
        .unwrap_or_else(|_| "deepgram".to_string())
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "mock" => (
            Some(Arc::new(
                matric_api::realtime::asr::MockAsrBackend::default(),
            )),
            None,
        ),
        "" | "disabled" | "none" => (None, None),
        "deepgram" => match matric_api::realtime::asr::deepgram::DeepgramBackend::from_env() {
            Ok(backend) => {
                let metrics = backend.metrics();
                (Some(Arc::new(backend)), Some(metrics))
            }
            Err(error) => {
                tracing::info!(
                    error_len = telemetry_text_len(&error.to_string()),
                    detail = API_PROVIDER_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "realtime_asr_backend_from_env",
                    "Realtime Deepgram ASR backend disabled"
                );
                (None, None)
            }
        },
        other => {
            tracing::warn!(
                backend_len = telemetry_text_len(other),
                detail = API_PROVIDER_DIAGNOSTIC_FAILURE_DETAIL,
                operation = "realtime_asr_backend_selection",
                "Unsupported REALTIME_ASR_BACKEND; realtime ASR disabled"
            );
            (None, None)
        }
    }
}

fn realtime_asr_deepgram_cost_per_minute() -> f64 {
    std::env::var("REALTIME_ASR_COST_DEEPGRAM_DOLLARS_PER_MINUTE")
        .ok()
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value >= 0.0)
        .unwrap_or(0.0036)
}

fn build_rtp_metrics(
    metrics: matric_db::call_sessions::RealtimeCallMetrics,
    deepgram_rate: f64,
    deepgram_metrics: Option<matric_api::realtime::asr::deepgram::DeepgramMetricsSnapshot>,
) -> serde_json::Value {
    let backend_seconds = metrics
        .duration_seconds_by_backend
        .as_object()
        .cloned()
        .unwrap_or_default();
    let deepgram_seconds = backend_seconds
        .get("deepgram")
        .and_then(|value| value.as_f64())
        .unwrap_or(0.0);
    let estimated_cost = (deepgram_seconds / 60.0) * deepgram_rate;
    let deepgram_metrics = deepgram_metrics.unwrap_or(
        matric_api::realtime::asr::deepgram::DeepgramMetricsSnapshot {
            partial_events: 0,
            final_events: 0,
            failover_total: 0,
            partial_latency_sum_ms: 0,
            partial_latency_buckets:
                matric_api::realtime::asr::deepgram::DeepgramPartialLatencyBuckets {
                    le_100: 0,
                    le_250: 0,
                    le_500: 0,
                    le_1000: 0,
                    le_2500: 0,
                    le_inf: 0,
                },
            last_partial_latency_ms: 0,
        },
    );

    serde_json::json!({
        "rtp_call_active_count": {
            "type": "gauge",
            "value": metrics.active_sessions,
            "labels": {}
        },
        "rtp_audio_frame_latency_ms": {
            "type": "histogram",
            "unit": "milliseconds",
            "buckets": [
                {"le": 10, "count": 0},
                {"le": 25, "count": 0},
                {"le": 50, "count": 0},
                {"le": 100, "count": 0},
                {"le": 250, "count": 0},
                {"le": "+Inf", "count": 0}
            ],
            "count": RTP_AUDIO_FRAMES_TOTAL.load(Ordering::Relaxed),
            "sum": 0
        },
        "rtp_codec_decode_failures_total": {
            "type": "counter",
            "value": RTP_CODEC_DECODE_FAILURES_TOTAL.load(Ordering::Relaxed),
            "labels": {"provider": "twilio"}
        },
        "rtp_asr_partial_latency_ms": {
            "type": "histogram",
            "unit": "milliseconds",
            "buckets": [
                {"le": 100, "count": deepgram_metrics.partial_latency_buckets.le_100},
                {"le": 250, "count": deepgram_metrics.partial_latency_buckets.le_250},
                {"le": 500, "count": deepgram_metrics.partial_latency_buckets.le_500},
                {"le": 1000, "count": deepgram_metrics.partial_latency_buckets.le_1000},
                {"le": 2500, "count": deepgram_metrics.partial_latency_buckets.le_2500},
                {"le": "+Inf", "count": deepgram_metrics.partial_latency_buckets.le_inf}
            ],
            "count": deepgram_metrics.partial_events,
            "sum": deepgram_metrics.partial_latency_sum_ms,
            "latest": deepgram_metrics.last_partial_latency_ms
        },
        "rtp_asr_failover_total": {
            "type": "counter",
            "value": deepgram_metrics.failover_total,
            "labels": {"backend": "deepgram"}
        },
        "rtp_outbox_write_failures_total": {
            "type": "counter",
            "value": RTP_OUTBOX_WRITE_FAILURES_TOTAL.load(Ordering::Relaxed)
        },
        "rtp_session_duration_seconds": {
            "type": "histogram",
            "unit": "seconds",
            "buckets": [
                {"le": 30, "count": metrics.duration_buckets.le_30},
                {"le": 60, "count": metrics.duration_buckets.le_60},
                {"le": 300, "count": metrics.duration_buckets.le_300},
                {"le": 900, "count": metrics.duration_buckets.le_900},
                {"le": 1800, "count": metrics.duration_buckets.le_1800},
                {"le": 3600, "count": metrics.duration_buckets.le_3600},
                {"le": "+Inf", "count": metrics.duration_buckets.le_inf}
            ],
            "count": metrics.completed_sessions,
            "sum": metrics.completed_duration_sum_seconds
        },
        "rtp_estimated_asr_cost_dollars_total": {
            "type": "counter",
            "value": estimated_cost,
            "rates_per_minute": {"deepgram": deepgram_rate},
            "duration_seconds_by_backend": backend_seconds
        },
        "session_totals": {
            "total": metrics.total_sessions,
            "active": metrics.active_sessions,
            "completed": metrics.completed_sessions
        }
    })
}

/// Live health check endpoint (readiness probe).
///
/// Performs concurrent live connectivity checks on all dependent services:
/// - PostgreSQL (SELECT 1)
/// - Redis search cache (connection check)
/// - Ollama vision backend (if configured)
/// - Whisper transcription backend (if configured)
///
/// Returns 200 for healthy or degraded (optional services down),
/// 503 when critical services (PostgreSQL) are unreachable.
#[utoipa::path(
    get,
    path = "/health/live",
    tag = "System",
    responses(
        (status = 200, description = "Healthy or degraded"),
        (status = 503, description = "Critical service unavailable"),
    )
)]
async fn health_check_live(State(state): State<AppState>) -> impl IntoResponse {
    let start = std::time::Instant::now();

    // Run all checks concurrently
    let (
        db_result,
        redis_result,
        inference_result,
        vision_result,
        transcription_result,
        ner_result,
        diarization_result,
    ) = tokio::join!(
        // PostgreSQL: SELECT 1 with 5s timeout
        async {
            match tokio::time::timeout(
                std::time::Duration::from_secs(5),
                sqlx::query_scalar::<_, i32>("SELECT 1").fetch_one(&state.db.pool),
            )
            .await
            {
                Ok(Ok(1)) => ("ok", None),
                Ok(Ok(_)) => ("ok", None),
                Ok(Err(_)) => (
                    "error",
                    Some(health_dependency_error_code("database_query")),
                ),
                Err(_) => (
                    "error",
                    Some(health_dependency_error_code("dependency_timeout")),
                ),
            }
        },
        // Redis: connection check
        async {
            if state.search_cache.is_connected().await {
                ("ok", None)
            } else {
                (
                    "unavailable",
                    Some(health_dependency_error_code("cache_unavailable")),
                )
            }
        },
        // Inference backend (Ollama generation/embedding) (#568)
        async {
            match state.generation_backend() {
                Some(backend) => match backend.health_check().await {
                    Ok(true) => ("ok", None),
                    Ok(false) => (
                        "error",
                        Some(health_dependency_error_code("provider_unreachable")),
                    ),
                    Err(_) => (
                        "error",
                        Some(health_dependency_error_code("provider_check")),
                    ),
                },
                None => (
                    "error",
                    Some(health_dependency_error_code("backend_not_initialized")),
                ),
            }
        },
        // Vision backend (optional)
        async {
            match &state.vision_backend {
                Some(backend) => match backend.health_check().await {
                    Ok(_) => ("ok", None),
                    Err(_) => (
                        "error",
                        Some(health_dependency_error_code("provider_check")),
                    ),
                },
                None => ("not_configured", None),
            }
        },
        // Transcription backend (optional)
        async {
            match &state.transcription_backend {
                Some(backend) => match backend.health_check().await {
                    Ok(_) => ("ok", None),
                    Err(_) => (
                        "error",
                        Some(health_dependency_error_code("provider_check")),
                    ),
                },
                None => ("not_configured", None),
            }
        },
        // GLiNER NER backend (optional)
        async {
            match &state.ner_backend {
                Some(backend) => match backend.health_check().await {
                    Ok(true) => ("ok", None),
                    Ok(false) => (
                        "error",
                        Some(health_dependency_error_code("provider_unhealthy")),
                    ),
                    Err(_) => (
                        "error",
                        Some(health_dependency_error_code("provider_check")),
                    ),
                },
                None => ("not_configured", None),
            }
        },
        // pyannote diarization backend (optional)
        async {
            match &state.diarization_backend {
                Some(backend) => match backend.health_check().await {
                    Ok(true) => ("ok", None),
                    Ok(false) => (
                        "error",
                        Some(health_dependency_error_code("provider_unhealthy")),
                    ),
                    Err(_) => (
                        "error",
                        Some(health_dependency_error_code("provider_check")),
                    ),
                },
                None => ("not_configured", None),
            }
        },
    );

    let elapsed_ms = start.elapsed().as_millis();

    // PostgreSQL is critical — if it's down, the service is unhealthy
    let db_healthy = db_result.0 == "ok";

    // Determine overall status
    let (overall_status, http_status) = if !db_healthy {
        ("unhealthy", StatusCode::SERVICE_UNAVAILABLE)
    } else if redis_result.0 == "error"
        || (inference_result.0 == "error")
        || (vision_result.0 == "error")
        || (transcription_result.0 == "error")
        || (ner_result.0 == "error")
        || (diarization_result.0 == "error")
    {
        ("degraded", StatusCode::OK)
    } else {
        ("healthy", StatusCode::OK)
    };

    let mut services = serde_json::json!({
        "postgresql": {
            "status": db_result.0,
        },
        "redis": {
            "status": redis_result.0,
        },
        "inference": {
            "status": inference_result.0,
        },
        "vision": {
            "status": vision_result.0,
        },
        "transcription": {
            "status": transcription_result.0,
        },
        "ner": {
            "status": ner_result.0,
        },
        "diarization": {
            "status": diarization_result.0,
        },
    });

    // Add stable dependency reason codes where present. These are client-safe
    // classifiers, not raw backend error messages.
    if let Some(err) = &db_result.1 {
        set_health_service_reason_code(&mut services, "postgresql", err);
    }
    if let Some(err) = &redis_result.1 {
        set_health_service_reason_code(&mut services, "redis", err);
    }
    if let Some(err) = &inference_result.1 {
        set_health_service_reason_code(&mut services, "inference", err);
    }
    if let Some(err) = &vision_result.1 {
        set_health_service_reason_code(&mut services, "vision", err);
    }
    if let Some(err) = &transcription_result.1 {
        set_health_service_reason_code(&mut services, "transcription", err);
    }
    if let Some(err) = &ner_result.1 {
        set_health_service_reason_code(&mut services, "ner", err);
    }
    if let Some(err) = &diarization_result.1 {
        set_health_service_reason_code(&mut services, "diarization", err);
    }

    let body = serde_json::json!({
        "status": overall_status,
        "version": env!("CARGO_PKG_VERSION"),
        "git_sha": state.git_sha,
        "build_date": state.build_date,
        "check_duration_ms": elapsed_ms,
        "services": services,
        "capabilities": {
            "vision": state.vision_backend.is_some(),
            "audio_transcription": state.transcription_backend.is_some(),
            "speaker_diarization": state.diarization_backend.is_some(),
            "ner": state.ner_backend.is_some(),
            "auth_required": state.require_auth,
            "extraction_strategies": state.extraction_strategies,
            "chat": {
                "available": state.generation_backend().is_some()
                    && state.inference_available.load(Ordering::Relaxed),
                "configured": state.generation_backend().is_some(),
                "max_concurrent": matric_core::defaults::chat_max_concurrent(),
            },
        },
    });

    (http_status, Json(body))
}

// =============================================================================
// NOTE HANDLERS
// =============================================================================

/// Parse relative time string (e.g., "7d", "1w", "2h") into a DateTime.
fn parse_relative_time(s: &str) -> Option<chrono::DateTime<chrono::Utc>> {
    let s = s.trim().to_lowercase();
    if s.is_empty() {
        return None;
    }

    // Parse the number and unit
    let mut num_str = String::new();
    let mut unit = String::new();
    for c in s.chars() {
        if c.is_ascii_digit() {
            num_str.push(c);
        } else {
            unit.push(c);
        }
    }

    let num: i64 = num_str.parse().ok()?;
    let duration = match unit.as_str() {
        "h" | "hr" | "hrs" | "hour" | "hours" => chrono::Duration::hours(num),
        "d" | "day" | "days" => chrono::Duration::days(num),
        "w" | "wk" | "week" | "weeks" => chrono::Duration::weeks(num),
        "m" | "mo" | "month" | "months" => chrono::Duration::days(num * 30),
        "min" | "mins" | "minute" | "minutes" => chrono::Duration::minutes(num),
        _ => return None,
    };

    Some(chrono::Utc::now() - duration)
}

// =============================================================================
// TEMPORAL QUERY HANDLERS
// =============================================================================

#[derive(Deserialize)]
struct TimelineQuery {
    /// Time period to group by: "hour", "day", "week", "month" (default: "day")
    period: Option<String>,
    /// Alias for period (MCP tools send "granularity")
    granularity: Option<String>,
    /// How many periods to look back (default: 30)
    periods: Option<i64>,
    /// Relative time filter: "7d" (7 days), "1w" (1 week), "1m" (1 month)
    since: Option<String>,
}

impl fmt::Debug for TimelineQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("TimelineQuery")
            .field("period_len", &self.period.as_ref().map(String::len))
            .field(
                "granularity_len",
                &self.granularity.as_ref().map(String::len),
            )
            .field("periods", &self.periods)
            .field("since_len", &self.since.as_ref().map(String::len))
            .finish()
    }
}

#[derive(Serialize)]
struct TimelineBucket {
    period_start: chrono::DateTime<chrono::Utc>,
    period_end: chrono::DateTime<chrono::Utc>,
    count: i64,
    note_ids: Vec<Uuid>,
}

impl std::fmt::Debug for TimelineBucket {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("TimelineBucket")
            .field("period_start", &self.period_start)
            .field("period_end", &self.period_end)
            .field("count", &self.count)
            .field("note_id_count", &self.note_ids.len())
            .finish()
    }
}

/// Get notes grouped by time periods for timeline visualization.
#[utoipa::path(
    get,
    path = "/api/v1/notes/timeline",
    tag = "Notes",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn get_notes_timeline(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<TimelineQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let period = query
        .granularity
        .as_deref()
        .or(query.period.as_deref())
        .unwrap_or("day");
    let periods_back = query
        .periods
        .unwrap_or(matric_core::defaults::TREND_PERIODS);

    // Calculate the cutoff date
    let since = query
        .since
        .as_ref()
        .and_then(|s| parse_relative_time(s))
        .unwrap_or_else(|| {
            let duration = match period {
                "hour" => chrono::Duration::hours(periods_back),
                "week" => chrono::Duration::weeks(periods_back),
                "month" => chrono::Duration::days(periods_back * 30),
                _ => chrono::Duration::days(periods_back), // default: day
            };
            chrono::Utc::now() - duration
        });

    // Query notes created since the cutoff
    let req = ListNotesRequest {
        limit: Some(1000), // reasonable limit
        offset: None,
        filter: None,
        sort_by: Some("created_at".to_string()),
        sort_order: Some("desc".to_string()),
        collection_id: None,
        tags: None,
        created_after: Some(since),
        created_before: None,
        updated_after: None,
        updated_before: None,
    };

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let response = ctx
        .query(move |tx| Box::pin(async move { notes.list_tx(tx, req).await }))
        .await?;

    // Group notes by period
    let mut buckets: std::collections::HashMap<i64, Vec<Uuid>> = std::collections::HashMap::new();

    for note in &response.notes {
        let bucket_key = match period {
            "hour" => {
                // Hour: timestamp / seconds_per_hour
                note.created_at_utc.timestamp() / 3600
            }
            "week" => {
                // Get start of week (Monday)
                let days_since_monday = note.created_at_utc.weekday().num_days_from_monday() as i64;
                (note.created_at_utc - chrono::Duration::days(days_since_monday)).timestamp()
                    / 86400
                    / 7
            }
            "month" => {
                // Year-month as a single number
                note.created_at_utc.year() as i64 * 12 + note.created_at_utc.month() as i64
            }
            _ => {
                // Day: timestamp / seconds_per_day
                note.created_at_utc.timestamp() / 86400
            }
        };

        buckets.entry(bucket_key).or_default().push(note.id);
    }

    // Convert to response format
    let mut timeline: Vec<TimelineBucket> = buckets
        .into_iter()
        .map(|(key, note_ids)| {
            let (period_start, period_end) = match period {
                "hour" => {
                    let start = chrono::DateTime::from_timestamp(key * 3600, 0)
                        .unwrap_or_else(chrono::Utc::now);
                    let end = start + chrono::Duration::hours(1);
                    (start, end)
                }
                "week" => {
                    let start = chrono::DateTime::from_timestamp(key * 7 * 86400, 0)
                        .unwrap_or_else(chrono::Utc::now);
                    let end = start + chrono::Duration::weeks(1);
                    (start, end)
                }
                "month" => {
                    let year = (key / 12) as i32;
                    let month = ((key % 12) + 1) as u32;
                    let start = chrono::DateTime::parse_from_rfc3339(&format!(
                        "{:04}-{:02}-01T00:00:00Z",
                        year, month
                    ))
                    .map(|dt| dt.with_timezone(&chrono::Utc))
                    .unwrap_or_else(|_| chrono::Utc::now());
                    let end = if month == 12 {
                        chrono::DateTime::parse_from_rfc3339(&format!(
                            "{:04}-01-01T00:00:00Z",
                            year + 1
                        ))
                        .map(|dt| dt.with_timezone(&chrono::Utc))
                        .unwrap_or_else(|_| chrono::Utc::now())
                    } else {
                        chrono::DateTime::parse_from_rfc3339(&format!(
                            "{:04}-{:02}-01T00:00:00Z",
                            year,
                            month + 1
                        ))
                        .map(|dt| dt.with_timezone(&chrono::Utc))
                        .unwrap_or_else(|_| chrono::Utc::now())
                    };
                    (start, end)
                }
                _ => {
                    let start = chrono::DateTime::from_timestamp(key * 86400, 0)
                        .unwrap_or_else(chrono::Utc::now);
                    let end = start + chrono::Duration::days(1);
                    (start, end)
                }
            };

            TimelineBucket {
                period_start,
                period_end,
                count: note_ids.len() as i64,
                note_ids,
            }
        })
        .collect();

    // Sort by period_start descending (most recent first)
    timeline.sort_by_key(|entry| std::cmp::Reverse(entry.period_start));

    Ok(Json(serde_json::json!({
        "period": period,
        "since": since,
        "total_notes": response.notes.len(),
        "buckets": timeline
    })))
}

#[derive(Deserialize)]
struct ActivityQuery {
    /// Relative time filter: "7d" (7 days), "1w" (1 week), "1m" (1 month)
    since: Option<String>,
    /// Limit number of results (default: 50)
    limit: Option<i64>,
    /// Comma-separated event types to filter by: created, updated
    event_types: Option<String>,
}

impl fmt::Debug for ActivityQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("ActivityQuery")
            .field("since_len", &self.since.as_ref().map(String::len))
            .field("limit", &self.limit)
            .field(
                "event_types_len",
                &self.event_types.as_ref().map(String::len),
            )
            .finish()
    }
}

#[derive(Serialize)]
struct ActivityEntry {
    note_id: Uuid,
    title: Option<String>,
    created_at: chrono::DateTime<chrono::Utc>,
    updated_at: chrono::DateTime<chrono::Utc>,
    is_recently_created: bool,
    is_recently_updated: bool,
}

impl std::fmt::Debug for ActivityEntry {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("ActivityEntry")
            .field("note_id_present", &true)
            .field("title_len", &self.title.as_ref().map(|value| value.len()))
            .field("created_at", &self.created_at)
            .field("updated_at", &self.updated_at)
            .field("is_recently_created", &self.is_recently_created)
            .field("is_recently_updated", &self.is_recently_updated)
            .finish()
    }
}

/// Get recent note activity (created and modified notes).
#[utoipa::path(
    get,
    path = "/api/v1/notes/activity",
    tag = "Notes",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn get_notes_activity(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<ActivityQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let since = query
        .since
        .as_ref()
        .and_then(|s| parse_relative_time(s))
        .unwrap_or_else(|| chrono::Utc::now() - chrono::Duration::days(7));

    let limit = query.limit.unwrap_or(matric_core::defaults::PAGE_LIMIT);

    // Parse event_types filter (comma-separated: "created", "updated")
    let filter_event_types: Option<Vec<String>> = query.event_types.as_ref().map(|et| {
        et.split(',')
            .map(|s| s.trim().to_lowercase())
            .filter(|s| !s.is_empty())
            .collect()
    });

    // Determine which queries are needed based on event_types filter
    let want_created = filter_event_types
        .as_ref()
        .is_none_or(|types| types.contains(&"created".to_string()));
    let want_updated = filter_event_types
        .as_ref()
        .is_none_or(|types| types.contains(&"updated".to_string()));

    // Only build and execute queries for requested event types
    let created_req = if want_created {
        Some(ListNotesRequest {
            limit: Some(limit),
            offset: None,
            filter: None,
            sort_by: Some("created_at".to_string()),
            sort_order: Some("desc".to_string()),
            collection_id: None,
            tags: None,
            created_after: Some(since),
            created_before: None,
            updated_after: None,
            updated_before: None,
        })
    } else {
        None
    };

    let updated_req = if want_updated {
        Some(ListNotesRequest {
            limit: Some(limit),
            offset: None,
            filter: None,
            sort_by: Some("updated_at".to_string()),
            sort_order: Some("desc".to_string()),
            collection_id: None,
            tags: None,
            created_after: None,
            created_before: None,
            updated_after: Some(since),
            updated_before: None,
        })
    } else {
        None
    };

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let (created_notes, updated_notes) = ctx
        .query(move |tx| {
            Box::pin(async move {
                let created = if let Some(req) = created_req {
                    notes.list_tx(tx, req).await?
                } else {
                    matric_core::ListNotesResponse {
                        notes: vec![],
                        total: 0,
                    }
                };
                let updated = if let Some(req) = updated_req {
                    notes.list_tx(tx, req).await?
                } else {
                    matric_core::ListNotesResponse {
                        notes: vec![],
                        total: 0,
                    }
                };
                Ok((created, updated))
            })
        })
        .await?;

    // Combine and deduplicate
    let mut activity: std::collections::HashMap<Uuid, ActivityEntry> =
        std::collections::HashMap::new();

    for note in &created_notes.notes {
        activity.insert(
            note.id,
            ActivityEntry {
                note_id: note.id,
                title: Some(note.title.clone()),
                created_at: note.created_at_utc,
                updated_at: note.updated_at_utc,
                is_recently_created: true,
                is_recently_updated: note.updated_at_utc
                    > note.created_at_utc + chrono::Duration::seconds(60),
            },
        );
    }

    for note in &updated_notes.notes {
        activity
            .entry(note.id)
            .and_modify(|e| e.is_recently_updated = true)
            .or_insert(ActivityEntry {
                note_id: note.id,
                title: Some(note.title.clone()),
                created_at: note.created_at_utc,
                updated_at: note.updated_at_utc,
                is_recently_created: note.created_at_utc >= since,
                is_recently_updated: true,
            });
    }

    // Sort by most recent activity
    let mut entries: Vec<ActivityEntry> = activity.into_values().collect();

    // Apply event_types filter if specified
    if let Some(ref types) = filter_event_types {
        let want_created = types.contains(&"created".to_string());
        let want_updated = types.contains(&"updated".to_string());
        entries.retain(|e| {
            (want_created && e.is_recently_created) || (want_updated && e.is_recently_updated)
        });
    }

    entries.sort_by(|a, b| {
        let a_time = a.updated_at.max(a.created_at);
        let b_time = b.updated_at.max(b.created_at);
        b_time.cmp(&a_time)
    });
    entries.truncate(limit as usize);

    Ok(Json(serde_json::json!({
        "since": since,
        "activity": entries,
        "created_count": created_notes.notes.len(),
        "updated_count": updated_notes.notes.len()
    })))
}

// =============================================================================
// KNOWLEDGE HEALTH DASHBOARD
// =============================================================================

#[derive(Deserialize)]
struct HealthQuery {
    /// Staleness threshold in days (default: 90)
    stale_days: Option<i64>,
    /// Limit for results (default: 100)
    limit: Option<i64>,
}

impl fmt::Debug for HealthQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("HealthQuery")
            .field("stale_days", &self.stale_days)
            .field("limit", &self.limit)
            .finish()
    }
}

/// Get overall knowledge health metrics.
#[utoipa::path(
    get,
    path = "/api/v1/health/knowledge",
    tag = "System",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn get_knowledge_health(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<HealthQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let stale_days = query
        .stale_days
        .unwrap_or(matric_core::defaults::STALE_DAYS);
    let stale_threshold = chrono::Utc::now() - chrono::Duration::days(stale_days);

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes_repo = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let links_repo = matric_db::PgLinkRepository::new(state.db.pool.clone());
    let tags_repo = matric_db::PgTagRepository::new(state.db.pool.clone());

    let mut tx = ctx.begin_tx().await?;

    // Get total note count
    let all_notes = notes_repo
        .list_tx(
            &mut tx,
            ListNotesRequest {
                limit: Some(matric_core::defaults::INTERNAL_FETCH_LIMIT),
                offset: None,
                filter: None,
                sort_by: None,
                sort_order: None,
                collection_id: None,
                tags: None,
                created_after: None,
                created_before: None,
                updated_after: None,
                updated_before: None,
            },
        )
        .await?;

    let total_notes = all_notes.total;

    // Count stale notes
    let stale_count = all_notes
        .notes
        .iter()
        .filter(|n| n.updated_at_utc < stale_threshold)
        .count();

    // Get notes without any links (unlinked)
    let all_links = links_repo
        .list_all_tx(&mut tx, matric_core::defaults::INTERNAL_FETCH_LIMIT, 0)
        .await
        .unwrap_or_default();
    let linked_note_ids: std::collections::HashSet<Uuid> = all_links
        .iter()
        .flat_map(|link| {
            let mut ids = vec![link.from_note_id];
            if let Some(to_id) = link.to_note_id {
                ids.push(to_id);
            }
            ids
        })
        .collect();
    let unlinked_count = all_notes
        .notes
        .iter()
        .filter(|n| !linked_note_ids.contains(&n.id))
        .count();

    // Get orphan tags (tags with no notes) and notes-without-tags count
    let all_tags = tags_repo.list_tx(&mut tx).await.unwrap_or_default();
    let orphan_tag_count = all_tags.iter().filter(|t| t.note_count == 0).count();

    // Count notes that have at least one tag
    let mut notes_with_tags: std::collections::HashSet<Uuid> = std::collections::HashSet::new();
    for note in &all_notes.notes {
        let note_tags = tags_repo
            .get_for_note_tx(&mut tx, note.id)
            .await
            .unwrap_or_default();
        if !note_tags.is_empty() {
            notes_with_tags.insert(note.id);
        }
    }
    let notes_without_tags = all_notes.notes.len() - notes_with_tags.len();

    drop(tx); // read-only, no commit needed

    // Calculate health score (0-100)
    let health_score = if total_notes > 0 {
        let stale_ratio = stale_count as f64 / total_notes as f64;
        let unlinked_ratio = unlinked_count as f64 / total_notes as f64;
        let untagged_ratio = notes_without_tags as f64 / total_notes as f64;

        let score = 100.0
            - (stale_ratio * matric_core::defaults::HEALTH_WEIGHT_STALE)
            - (unlinked_ratio * matric_core::defaults::HEALTH_WEIGHT_UNLINKED)
            - (untagged_ratio * matric_core::defaults::HEALTH_WEIGHT_UNTAGGED);
        score.clamp(0.0, 100.0) as i64
    } else {
        100
    };

    // Generate actionable recommendations based on health data
    let mut recommendations: Vec<serde_json::Value> = Vec::new();
    if total_notes > 0 {
        if stale_count > 0 {
            recommendations.push(serde_json::json!({
                "type": "stale_notes",
                "message": format!("{} notes haven't been updated in {} days", stale_count, stale_days),
                "action": "Review stale notes and update or archive them",
                "severity": if stale_count as f64 / total_notes as f64 > 0.5 { "high" } else { "medium" }
            }));
        }
        if unlinked_count > 0 {
            recommendations.push(serde_json::json!({
                "type": "unlinked_notes",
                "message": format!("{} notes have no semantic links", unlinked_count),
                "action": "Use reprocess_note with steps=[\"linking\"] to auto-link isolated notes",
                "severity": if unlinked_count as f64 / total_notes as f64 > 0.5 { "high" } else { "medium" }
            }));
        }
        if notes_without_tags > 0 {
            recommendations.push(serde_json::json!({
                "type": "untagged_notes",
                "message": format!("{} notes have no tags or concepts", notes_without_tags),
                "action": "Tag notes with relevant concepts for better discoverability",
                "severity": if notes_without_tags as f64 / total_notes as f64 > 0.5 { "high" } else { "medium" }
            }));
        }
    }
    if orphan_tag_count > 0 {
        recommendations.push(serde_json::json!({
            "type": "orphan_tags",
            "message": format!("{} tags are not used by any notes", orphan_tag_count),
            "action": "Review orphan tags via get_orphan_tags and clean up unused tags",
            "severity": "low"
        }));
    }

    // Blob storage metrics (#531) — uses psql for consistency with get_storage_breakdown
    let blob_count = get_db_size_via_psql("COUNT(*) FROM attachment_blob").unwrap_or(0);
    let blob_total_bytes =
        get_db_size_via_psql("COALESCE(SUM(size_bytes), 0) FROM attachment_blob").unwrap_or(0);
    let orphaned_blob_count =
        get_db_size_via_psql("COUNT(*) FROM attachment_blob WHERE reference_count = 0")
            .unwrap_or(0);
    let orphaned_blob_bytes = get_db_size_via_psql(
        "COALESCE(SUM(size_bytes), 0) FROM attachment_blob WHERE reference_count = 0",
    )
    .unwrap_or(0);

    if orphaned_blob_count > 0 {
        recommendations.push(serde_json::json!({
            "type": "orphaned_blobs",
            "message": format!("{} orphaned blobs consuming {}", orphaned_blob_count, format_size(orphaned_blob_bytes as u64)),
            "action": "Run cleanup_orphaned_blobs() or delete unreferenced attachments to reclaim storage",
            "severity": if orphaned_blob_bytes > 100_000_000 { "high" } else { "medium" }
        }));
    }

    Ok(Json(serde_json::json!({
        "health_score": health_score,
        "total_notes": total_notes,
        "stale_notes": stale_count,
        "stale_threshold_days": stale_days,
        "unlinked_notes": unlinked_count,
        "notes_without_tags": notes_without_tags,
        "orphan_tags": orphan_tag_count,
        "total_tags": all_tags.len(),
        "total_links": all_links.len(),
        "blob_storage": {
            "total_blobs": blob_count,
            "total_size_bytes": blob_total_bytes,
            "total_size_human": format_size(blob_total_bytes as u64),
            "orphaned_blobs": orphaned_blob_count,
            "orphaned_size_bytes": orphaned_blob_bytes,
            "orphaned_size_human": format_size(orphaned_blob_bytes as u64),
        },
        "metrics": {
            "stale_ratio": if total_notes > 0 { stale_count as f64 / total_notes as f64 } else { 0.0 },
            "unlinked_ratio": if total_notes > 0 { unlinked_count as f64 / total_notes as f64 } else { 0.0 },
            "untagged_ratio": if total_notes > 0 { notes_without_tags as f64 / total_notes as f64 } else { 0.0 },
            "tag_coverage": if total_notes > 0 { 1.0 - (notes_without_tags as f64 / total_notes as f64) } else { 1.0 },
            "link_coverage": if total_notes > 0 { 1.0 - (unlinked_count as f64 / total_notes as f64) } else { 1.0 }
        },
        "recommendations": recommendations
    })))
}

/// Get tags not used by any notes (true orphan tags).
#[utoipa::path(
    get,
    path = "/api/v1/health/orphan-tags",
    tag = "System",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn get_orphan_tags(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<HealthQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let limit = query
        .limit
        .unwrap_or(matric_core::defaults::PAGE_LIMIT_LARGE) as usize;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let tags_repo = matric_db::PgTagRepository::new(state.db.pool.clone());
    let mut tx = ctx.begin_tx().await?;

    // list_tx returns all tags with note_count via LEFT JOIN
    let all_tags = tags_repo.list_tx(&mut tx).await.unwrap_or_default();

    drop(tx);

    // Filter to true orphan tags (note_count == 0)
    let orphan_tags: Vec<serde_json::Value> = all_tags
        .into_iter()
        .filter(|tag| tag.note_count == 0)
        .take(limit)
        .map(|tag| {
            serde_json::json!({
                "tag": tag.name,
                "created_at": tag.created_at_utc
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "orphan_tags": orphan_tags,
        "count": orphan_tags.len()
    })))
}

/// Get notes not updated in a long time.
#[utoipa::path(
    get,
    path = "/api/v1/health/stale-notes",
    tag = "System",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn get_stale_notes(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<HealthQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let stale_days = query
        .stale_days
        .unwrap_or(matric_core::defaults::STALE_DAYS);
    let limit = query
        .limit
        .unwrap_or(matric_core::defaults::PAGE_LIMIT_LARGE) as usize;
    let stale_threshold = chrono::Utc::now() - chrono::Duration::days(stale_days);

    let req_for_query = ListNotesRequest {
        limit: Some(matric_core::defaults::INTERNAL_FETCH_LIMIT),
        offset: None,
        filter: None,
        sort_by: Some("updated_at".to_string()),
        sort_order: Some("asc".to_string()),
        collection_id: None,
        tags: None,
        created_after: None,
        created_before: None,
        updated_after: None,
        updated_before: Some(stale_threshold),
    };

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let all_notes = ctx
        .query(move |tx| Box::pin(async move { notes.list_tx(tx, req_for_query).await }))
        .await?;

    let stale_notes: Vec<serde_json::Value> = all_notes
        .notes
        .iter()
        .take(limit)
        .map(|n| {
            let days_stale = (chrono::Utc::now() - n.updated_at_utc).num_days();
            serde_json::json!({
                "id": n.id,
                "title": n.title,
                "updated_at": n.updated_at_utc,
                "days_stale": days_stale
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "stale_threshold_days": stale_days,
        "stale_notes": stale_notes,
        "count": stale_notes.len()
    })))
}

/// Get notes with no incoming or outgoing links.
#[utoipa::path(
    get,
    path = "/api/v1/health/unlinked-notes",
    tag = "System",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn get_unlinked_notes(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<HealthQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let limit = query
        .limit
        .unwrap_or(matric_core::defaults::PAGE_LIMIT_LARGE) as usize;

    let req = ListNotesRequest {
        limit: Some(matric_core::defaults::INTERNAL_FETCH_LIMIT),
        offset: None,
        filter: None,
        sort_by: Some("created_at".to_string()),
        sort_order: Some("desc".to_string()),
        collection_id: None,
        tags: None,
        created_after: None,
        created_before: None,
        updated_after: None,
        updated_before: None,
    };

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes_repo = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let links_repo = matric_db::PgLinkRepository::new(state.db.pool.clone());
    let (all_links, all_notes) = ctx
        .query(move |tx| {
            Box::pin(async move {
                let links = links_repo
                    .list_all_tx(tx, matric_core::defaults::INTERNAL_FETCH_LIMIT, 0)
                    .await
                    .unwrap_or_default();
                let notes = notes_repo.list_tx(tx, req).await?;
                Ok((links, notes))
            })
        })
        .await?;

    let linked_note_ids: std::collections::HashSet<Uuid> = all_links
        .iter()
        .flat_map(|link| {
            let mut ids = vec![link.from_note_id];
            if let Some(to_id) = link.to_note_id {
                ids.push(to_id);
            }
            ids
        })
        .collect();

    // Filter to unlinked notes
    let unlinked_notes: Vec<serde_json::Value> = all_notes
        .notes
        .iter()
        .filter(|n| !linked_note_ids.contains(&n.id))
        .take(limit)
        .map(|n| {
            serde_json::json!({
                "id": n.id,
                "title": n.title,
                "created_at": n.created_at_utc
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "unlinked_notes": unlinked_notes,
        "count": unlinked_notes.len(),
        "total_notes": all_notes.total,
        "linked_notes": linked_note_ids.len()
    })))
}

/// Get tag co-occurrence patterns.
#[utoipa::path(
    get,
    path = "/api/v1/health/tag-cooccurrence",
    tag = "System",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn get_tag_cooccurrence(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<HealthQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let limit = query.limit.unwrap_or(matric_core::defaults::PAGE_LIMIT) as usize;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes_repo = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let tags_repo = matric_db::PgTagRepository::new(state.db.pool.clone());
    let mut tx = ctx.begin_tx().await?;

    // Get all notes
    let all_notes = notes_repo
        .list_tx(
            &mut tx,
            ListNotesRequest {
                limit: Some(matric_core::defaults::INTERNAL_FETCH_LIMIT),
                offset: None,
                filter: None,
                sort_by: None,
                sort_order: None,
                collection_id: None,
                tags: None,
                created_after: None,
                created_before: None,
                updated_after: None,
                updated_before: None,
            },
        )
        .await?;

    // Build co-occurrence matrix
    let mut cooccurrence: std::collections::HashMap<(String, String), i64> =
        std::collections::HashMap::new();

    for note in &all_notes.notes {
        let note_tags = tags_repo
            .get_for_note_tx(&mut tx, note.id)
            .await
            .unwrap_or_default();
        // Generate all pairs
        for i in 0..note_tags.len() {
            for j in (i + 1)..note_tags.len() {
                let (a, b) = if note_tags[i] < note_tags[j] {
                    (note_tags[i].clone(), note_tags[j].clone())
                } else {
                    (note_tags[j].clone(), note_tags[i].clone())
                };
                *cooccurrence.entry((a, b)).or_insert(0) += 1;
            }
        }
    }

    drop(tx);

    // Sort by frequency and take top pairs
    let mut pairs: Vec<_> = cooccurrence.into_iter().collect();
    pairs.sort_by_key(|pair| std::cmp::Reverse(pair.1));

    let top_pairs: Vec<serde_json::Value> = pairs
        .into_iter()
        .take(limit)
        .map(|((tag_a, tag_b), count)| {
            serde_json::json!({
                "tag_a": tag_a,
                "tag_b": tag_b,
                "count": count
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "cooccurrence_pairs": top_pairs,
        "count": top_pairs.len()
    })))
}

/// Query parameters for access frequency analytics.
#[derive(Deserialize)]
struct AccessFrequencyQuery {
    /// Number of results (default: 50)
    limit: Option<i64>,
    /// Sort mode: "most_accessed" (default), "least_accessed", "recent_hot", "recent_cold"
    sort: Option<String>,
    /// Only include notes accessed at least this many times (default: 0)
    min_accesses: Option<i64>,
    /// Only include notes accessed fewer than this many times
    max_accesses: Option<i64>,
}

impl fmt::Debug for AccessFrequencyQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("AccessFrequencyQuery")
            .field("limit", &self.limit)
            .field("sort_len", &self.sort.as_ref().map(String::len))
            .field("min_accesses", &self.min_accesses)
            .field("max_accesses", &self.max_accesses)
            .finish()
    }
}

/// Get note access frequency analytics.
///
/// Returns notes ranked by access patterns: most/least accessed, recently hot/cold.
/// Supports both the aggregate `access_count` on the note table and the detailed
/// `note_access_log` for time-windowed analysis.
#[utoipa::path(
    get,
    path = "/api/v1/health/access-frequency",
    tag = "System",
    params(
        ("limit" = Option<i64>, Query, description = "Max results"),
        ("sort" = Option<String>, Query, description = "Sort mode: most_accessed, least_accessed, recent_hot, recent_cold"),
        ("min_accesses" = Option<i64>, Query, description = "Minimum access count filter"),
        ("max_accesses" = Option<i64>, Query, description = "Maximum access count filter"),
    ),
    responses(
        (status = 200, description = "Access frequency report"),
    )
)]
async fn get_access_frequency(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<AccessFrequencyQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let limit = query.limit.unwrap_or(50).min(500);
    let sort = query.sort.as_deref().unwrap_or("most_accessed");
    let min_accesses = query.min_accesses.unwrap_or(0);

    let ctx = state.db.for_schema(&archive_ctx.schema)?;

    let order_clause = match sort {
        "least_accessed" => "n.access_count ASC, n.created_at_utc DESC",
        "recent_hot" => "COALESCE(al.recent_7d, 0) DESC, n.access_count DESC",
        "recent_cold" => "COALESCE(al.recent_7d, 0) ASC, n.last_accessed_at ASC NULLS FIRST",
        _ => "n.access_count DESC, n.last_accessed_at DESC NULLS LAST", // most_accessed
    };

    let max_access_clause = if let Some(max) = query.max_accesses {
        format!("AND n.access_count < {}", max)
    } else {
        String::new()
    };

    let sql = format!(
        r#"
        SELECT
            n.id, n.title, n.access_count, n.last_accessed_at, n.created_at_utc,
            n.updated_at_utc, n.archived,
            COALESCE(al.recent_7d, 0)::BIGINT AS recent_7d,
            COALESCE(al.recent_30d, 0)::BIGINT AS recent_30d
        FROM note n
        LEFT JOIN LATERAL (
            SELECT
                COUNT(*) FILTER (WHERE accessed_at > NOW() - INTERVAL '7 days') AS recent_7d,
                COUNT(*) FILTER (WHERE accessed_at > NOW() - INTERVAL '30 days') AS recent_30d
            FROM note_access_log nal
            WHERE nal.note_id = n.id
        ) al ON true
        WHERE n.deleted_at IS NULL
          AND n.access_count >= $1
          {max_access_clause}
        ORDER BY {order_clause}
        LIMIT $2
        "#,
    );

    // Use sqlx::query_as with a typed struct to avoid needing sqlx::Row trait in scope
    #[derive(sqlx::FromRow)]
    struct AccessRow {
        id: Uuid,
        title: Option<String>,
        access_count: Option<i32>,
        last_accessed_at: Option<chrono::DateTime<chrono::Utc>>,
        created_at_utc: chrono::DateTime<chrono::Utc>,
        #[allow(dead_code)]
        updated_at_utc: chrono::DateTime<chrono::Utc>,
        archived: Option<bool>,
        recent_7d: i64,
        recent_30d: i64,
    }

    let rows: Vec<AccessRow> = ctx
        .query(move |tx| {
            Box::pin(async move {
                let rows = sqlx::query_as::<_, AccessRow>(&sql)
                    .bind(min_accesses)
                    .bind(limit)
                    .fetch_all(&mut **tx)
                    .await
                    .map_err(matric_core::Error::Database)?;
                Ok(rows)
            })
        })
        .await?;

    let notes: Vec<serde_json::Value> = rows
        .iter()
        .map(|r| {
            let access_count = r.access_count.unwrap_or(0);
            let days_since_access = r
                .last_accessed_at
                .map(|la| (chrono::Utc::now() - la).num_days())
                .unwrap_or(-1);

            serde_json::json!({
                "id": r.id,
                "title": r.title,
                "access_count": access_count,
                "recent_7d": r.recent_7d,
                "recent_30d": r.recent_30d,
                "last_accessed_at": r.last_accessed_at,
                "days_since_access": days_since_access,
                "created_at": r.created_at_utc,
                "archived": r.archived.unwrap_or(false),
            })
        })
        .collect();

    // Compute summary stats
    #[derive(sqlx::FromRow)]
    struct CountRow {
        cnt: i64,
    }

    let total_notes: i64 = {
        let schema = archive_ctx.schema.clone();
        let ctx2 = state.db.for_schema(&schema)?;
        ctx2.query(move |tx| {
            Box::pin(async move {
                let row = sqlx::query_as::<_, CountRow>(
                    "SELECT COUNT(*) as cnt FROM note WHERE deleted_at IS NULL",
                )
                .fetch_one(&mut **tx)
                .await
                .map_err(matric_core::Error::Database)?;
                Ok(row.cnt)
            })
        })
        .await?
    };

    let never_accessed: i64 = {
        let schema = archive_ctx.schema.clone();
        let ctx3 = state.db.for_schema(&schema)?;
        ctx3.query(move |tx| {
            Box::pin(async move {
                let row = sqlx::query_as::<_, CountRow>(
                    "SELECT COUNT(*) as cnt FROM note WHERE deleted_at IS NULL AND access_count = 0",
                )
                .fetch_one(&mut **tx)
                .await
                .map_err(matric_core::Error::Database)?;
                Ok(row.cnt)
            })
        })
        .await?
    };

    Ok(Json(serde_json::json!({
        "sort": sort,
        "notes": notes,
        "count": notes.len(),
        "summary": {
            "total_notes": total_notes,
            "never_accessed": never_accessed,
            "never_accessed_pct": if total_notes > 0 {
                (never_accessed as f64 / total_notes as f64 * 100.0).round()
            } else {
                0.0
            }
        }
    })))
}

#[derive(Deserialize)]
struct ListNotesQuery {
    limit: Option<i64>,
    offset: Option<i64>,
    filter: Option<String>,
    sort_by: Option<String>,
    sort_order: Option<String>,
    collection_id: Option<Uuid>,
    /// Filter by tags (comma-separated)
    tags: Option<String>,
    /// Filter: notes created after this timestamp (ISO 8601, timezone optional - assumes UTC)
    created_after: Option<FlexibleDateTime>,
    /// Filter: notes created before this timestamp (ISO 8601, timezone optional - assumes UTC)
    created_before: Option<FlexibleDateTime>,
    /// Filter: notes updated after this timestamp (ISO 8601, timezone optional - assumes UTC)
    updated_after: Option<FlexibleDateTime>,
    /// Filter: notes updated before this timestamp (ISO 8601, timezone optional - assumes UTC)
    updated_before: Option<FlexibleDateTime>,
    /// Relative time filter: "7d" (7 days), "1w" (1 week), "1m" (1 month), "2h" (2 hours)
    since: Option<String>,
}

impl fmt::Debug for ListNotesQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("ListNotesQuery")
            .field("limit", &self.limit)
            .field("offset", &self.offset)
            .field("filter_len", &self.filter.as_ref().map(String::len))
            .field("sort_by_len", &self.sort_by.as_ref().map(String::len))
            .field("sort_order_len", &self.sort_order.as_ref().map(String::len))
            .field("collection_id_set", &self.collection_id.is_some())
            .field("tags_len", &self.tags.as_ref().map(String::len))
            .field("created_after_set", &self.created_after.is_some())
            .field("created_before_set", &self.created_before.is_some())
            .field("updated_after_set", &self.updated_after.is_some())
            .field("updated_before_set", &self.updated_before.is_some())
            .field("since_len", &self.since.as_ref().map(String::len))
            .finish()
    }
}

#[utoipa::path(
    get,
    path = "/api/v1/notes",
    tag = "Notes",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn list_notes(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<ListNotesQuery>,
) -> Result<impl IntoResponse, ApiError> {
    // Issue #271 + #29: Validate limit parameter before database query
    // limit=0 is valid and returns an empty array (count-only queries)
    if let Some(limit) = query.limit {
        if limit < 0 {
            return Err(ApiError::BadRequest("limit must be >= 0".into()));
        }
    }

    // Parse comma-separated tags into Vec
    let tags = query.tags.map(|t| {
        t.split(',')
            .map(|s| s.trim().to_string())
            .filter(|s| !s.is_empty())
            .collect::<Vec<_>>()
    });

    // Parse relative time (e.g., "7d", "1w") and use as created_after if provided
    // FlexibleDateTime converts to DateTime<Utc> via into_inner()
    let created_after = query
        .created_after
        .map(|dt| dt.into_inner())
        .or_else(|| query.since.as_ref().and_then(|s| parse_relative_time(s)));

    let req = ListNotesRequest {
        limit: query.limit,
        offset: query.offset,
        filter: query.filter,
        sort_by: query.sort_by,
        sort_order: query.sort_order,
        collection_id: query.collection_id,
        tags,
        created_after,
        created_before: query.created_before.map(|dt| dt.into_inner()),
        updated_after: query.updated_after.map(|dt| dt.into_inner()),
        updated_before: query.updated_before.map(|dt| dt.into_inner()),
    };

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let response = ctx
        .query(move |tx| Box::pin(async move { notes.list_tx(tx, req).await }))
        .await?;
    Ok(Json(response))
}

#[derive(Deserialize, utoipa::ToSchema)]
struct CreateNoteBody {
    content: String,
    format: Option<String>,
    source: Option<String>,
    collection_id: Option<Uuid>,
    tags: Option<Vec<String>>,
    /// Optional explicit title. When provided, the AI title-generation
    /// pipeline step is skipped — caller's value wins. Useful for
    /// bulk-import paths like the shard rebuild that want deterministic
    /// titles without depending on inference. Added for #675.
    #[serde(default)]
    title: Option<String>,
    /// AI revision mode: "full", "light" (default), or "none"
    #[serde(default)]
    revision_mode: Option<String>,
    #[serde(default)]
    metadata: Option<serde_json::Value>,
    /// Optional document type ID for explicit typing (auto-detected if omitted)
    document_type_id: Option<Uuid>,
    /// Optional document type slug for explicit typing (e.g. "python-source", "markdown-document").
    /// Resolved to document_type_id via name lookup. Takes precedence over document_type_id if both set.
    #[serde(default)]
    document_type: Option<String>,
    /// Optional language model slug for AI operations (e.g. "qwen3:8b").
    /// If omitted, uses the globally configured default.
    #[serde(default)]
    model: Option<String>,
    /// Maximum characters per revision chunk. Overrides the auto-computed value
    /// from the model's context window. Set to 0 to disable chunking (single-pass).
    /// Must be >= 2000 if provided and > 0.
    #[serde(default)]
    chunk_max_chars: Option<usize>,
    /// Character overlap between adjacent revision chunks for context continuity.
    /// Default: 0 (revision chunks are independent).
    #[serde(default)]
    chunk_overlap: Option<usize>,
    /// Optional list of pipeline features to run after note creation.
    /// When omitted or null, the full default pipeline runs (backwards compatible).
    /// When set to an empty array `[]`, no AI processing runs (store only).
    /// When set to specific features, only those pipeline stages are queued.
    ///
    /// Available features:
    /// - `"revision"` — AI revision/rewrite of content
    /// - `"title_generation"` — auto-generate title from content
    /// - `"reference_extraction"` — extract references from content
    /// - `"metadata_extraction"` — extract metadata from content
    /// - `"document_type_inference"` — infer document type
    /// - `"concept_tagging"` — concept tagging (chains from revision if both enabled)
    #[serde(default)]
    pipeline: Option<Vec<String>>,
}

impl fmt::Debug for CreateNoteBody {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("CreateNoteBody")
            .field("content_len", &self.content.len())
            .field("format_len", &self.format.as_ref().map(String::len))
            .field("source_len", &self.source.as_ref().map(String::len))
            .field("collection_id_set", &self.collection_id.is_some())
            .field("tags_count", &self.tags.as_ref().map(Vec::len))
            .field(
                "tag_lens",
                &self
                    .tags
                    .as_ref()
                    .map(|tags| tags.iter().map(String::len).collect::<Vec<_>>()),
            )
            .field("title_len", &self.title.as_ref().map(String::len))
            .field(
                "revision_mode_len",
                &self.revision_mode.as_ref().map(String::len),
            )
            .field("metadata_set", &self.metadata.is_some())
            .field("document_type_id_set", &self.document_type_id.is_some())
            .field(
                "document_type_len",
                &self.document_type.as_ref().map(String::len),
            )
            .field("model_len", &self.model.as_ref().map(String::len))
            .field("chunk_max_chars", &self.chunk_max_chars)
            .field("chunk_overlap", &self.chunk_overlap)
            .field("pipeline_count", &self.pipeline.as_ref().map(Vec::len))
            .field(
                "pipeline_lens",
                &self
                    .pipeline
                    .as_ref()
                    .map(|pipeline| pipeline.iter().map(String::len).collect::<Vec<_>>()),
            )
            .finish()
    }
}

#[utoipa::path(
    post,
    path = "/api/v1/notes",
    tag = "Notes",
    request_body = CreateNoteBody,
    responses(
        (status = 201, description = "Created"),
        (status = 400, description = "Bad request"),
    )
)]
async fn create_note(
    _auth: Auth,
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Json(body): Json<CreateNoteBody>,
) -> Result<impl IntoResponse, ApiError> {
    // Validate revision_mode (returns 400 for invalid values)
    let mut revision_mode = parse_revision_mode(body.revision_mode.as_deref())?;
    let caller_set_revision_mode = body.revision_mode.is_some();

    // Validate chunking parameters (#572)
    validate_chunking_params(body.chunk_max_chars, body.chunk_overlap)
        .map_err(ApiError::BadRequest)?;

    // Resolve document_type slug to UUID if provided (slug takes precedence over UUID).
    // Also extract agent_hints that control NLP pipeline behavior (#563).
    let mut skip_title_gen = false;
    let resolved_doc_type_id = if let Some(ref slug) = body.document_type {
        match state.db.document_types.get_by_name(slug).await? {
            Some(dt) => {
                // When the caller didn't explicitly set revision_mode, respect
                // the document type's agent_hints (e.g. agent-reflection skips
                // revision and title generation automatically). (#563)
                if !caller_set_revision_mode
                    && dt
                        .agentic_config
                        .agent_hints
                        .get("skip_revision")
                        .and_then(|v| v.as_bool())
                        .unwrap_or(false)
                {
                    revision_mode = RevisionMode::None;
                }
                skip_title_gen = dt
                    .agentic_config
                    .agent_hints
                    .get("skip_title_generation")
                    .and_then(|v| v.as_bool())
                    .unwrap_or(false);
                Some(dt.id)
            }
            None => return Err(unknown_document_type(None)),
        }
    } else {
        body.document_type_id
    };

    // Extract tags for SKOS processing
    let tags_for_skos = body.tags.clone();

    // When the caller supplied an explicit title (#675), skip AI
    // title generation regardless of the document type's agent hints —
    // operator-supplied data wins.
    if body.title.as_deref().is_some_and(|s| !s.is_empty()) {
        skip_title_gen = true;
    }

    let req = CreateNoteRequest {
        content: body.content,
        format: body.format.unwrap_or_else(|| "markdown".to_string()),
        source: body.source.unwrap_or_else(|| "api".to_string()),
        collection_id: body.collection_id,
        tags: body.tags, // Legacy flat tags still inserted for backwards compatibility
        metadata: body.metadata,
        document_type_id: resolved_doc_type_id,
        title: body.title,
    };

    // Insert note (archive-scoped via SchemaContext)
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let req_clone = req.clone();
    let note_id = ctx
        .execute(move |tx| Box::pin(async move { notes.insert_tx(tx, req_clone).await }))
        .await?;

    // Determine schema for background jobs (Issue #109)
    let schema_for_jobs = if archive_ctx.schema != "public" {
        Some(archive_ctx.schema.as_str())
    } else {
        None
    };

    // Validate tag depth and length before processing (fixes #193, #189)
    if let Some(ref tags) = tags_for_skos {
        for tag in tags {
            if tag.len() > matric_core::defaults::TAG_NAME_MAX_LENGTH {
                return Err(tag_length_validation_error(None));
            }
            let depth = tag
                .split('/')
                .map(|s| s.trim())
                .filter(|s| !s.is_empty())
                .count();
            if depth > matric_core::tags::MAX_TAG_PATH_DEPTH {
                return Err(tag_depth_validation_error(None));
            }
        }
    }

    // Resolve tags via SKOS and create parent hierarchy (fixes #301)
    if let Some(tags) = tags_for_skos {
        let skos = matric_db::PgSkosRepository::new(state.db.pool.clone());
        let ctx_for_tags = state.db.for_schema(&archive_ctx.schema)?;

        let _ = ctx_for_tags
            .execute(move |tx| {
                Box::pin(async move {
                    let mut concept_ids = Vec::new();
                    for tag in &tags {
                        // Parse hierarchical tag (e.g., "programming/rust" -> ["programming", "rust"])
                        let tag_input = TagInput::parse(tag);
                        // Resolve or create SKOS concepts (auto-creates parent tags)
                        if let Ok(resolved) = skos.resolve_or_create_tag_tx(tx, &tag_input).await {
                            concept_ids.push(resolved.concept_id);
                        }
                    }
                    // Tag the note with resolved SKOS concepts
                    if !concept_ids.is_empty() {
                        let batch_req = BatchTagNoteRequest {
                            note_id,
                            concept_ids,
                            source: "user".to_string(),
                            confidence: None,
                            created_by: None,
                        };
                        skos.batch_tag_note_tx(tx, batch_req).await?;
                    }
                    Ok::<_, matric_core::Error>(())
                })
            })
            .await;
    }

    // When revision_mode is "none", insert_tx already populated note_revised_current
    // with the original content (for FTS). We intentionally skip update_revised() here
    // to avoid creating a fake note_revision history entry (#625).

    // Queue NLP pipeline with archive context (Issue #109)
    // Use inner variant to pass document-type-driven pipeline hints (#563)
    // and caller-defined feature selection (#628)
    queue_nlp_pipeline_inner(
        &state.db,
        note_id,
        revision_mode,
        &state.event_bus,
        schema_for_jobs,
        body.model.as_deref(),
        skip_title_gen,
        body.chunk_max_chars,
        body.chunk_overlap,
        body.pipeline.as_deref(),
    )
    .await;

    // Emit NoteCreated event (Issue #453, scoped via #452)
    let tags_for_event = state
        .db
        .tags
        .get_for_note(note_id)
        .await
        .unwrap_or_default();
    state.event_bus.emit_with_context(
        ServerEvent::NoteCreated {
            note_id,
            title: None, // Title not yet generated
            tags: tags_for_event,
        },
        event_context_for(&archive_ctx),
    );

    // Invalidate search cache so new note appears in search results (#341)
    state.search_cache.invalidate_all().await;

    Ok((
        StatusCode::CREATED,
        Json(serde_json::json!({ "id": note_id })),
    ))
}

