#[derive(Deserialize, utoipa::ToSchema)]
struct UpdateNoteBody {
    content: Option<String>,
    starred: Option<bool>,
    archived: Option<bool>,
    /// AI revision mode: "full" (default), "light", or "none"
    #[serde(default)]
    revision_mode: Option<String>,
    metadata: Option<serde_json::Value>,
    /// Replace all tags on this note (full replacement, not merge)
    tags: Option<Vec<String>>,
    /// Optional language model slug for AI operations (e.g. "qwen3:8b").
    /// If omitted, uses the globally configured default.
    #[serde(default)]
    model: Option<String>,
    /// Maximum characters per revision chunk. See CreateNoteBody for details.
    #[serde(default)]
    chunk_max_chars: Option<usize>,
    /// Character overlap between adjacent revision chunks. See CreateNoteBody for details.
    #[serde(default)]
    chunk_overlap: Option<usize>,
}

impl fmt::Debug for UpdateNoteBody {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("UpdateNoteBody")
            .field("content_len", &self.content.as_ref().map(String::len))
            .field("starred", &self.starred)
            .field("archived", &self.archived)
            .field(
                "revision_mode_len",
                &self.revision_mode.as_ref().map(String::len),
            )
            .field("metadata_set", &self.metadata.is_some())
            .field("tags_count", &self.tags.as_ref().map(Vec::len))
            .field(
                "tag_lens",
                &self
                    .tags
                    .as_ref()
                    .map(|tags| tags.iter().map(String::len).collect::<Vec<_>>()),
            )
            .field("model_len", &self.model.as_ref().map(String::len))
            .field("chunk_max_chars", &self.chunk_max_chars)
            .field("chunk_overlap", &self.chunk_overlap)
            .finish()
    }
}

#[utoipa::path(
    patch,
    path = "/api/v1/notes/{id}",
    tag = "Notes",
    params(
        ("id" = Uuid, Path, description = "Note ID")
    ),
    request_body = UpdateNoteBody,
    responses(
        (status = 200, description = "Success"),
        (status = 404, description = "Not found"),
        (status = 400, description = "Bad request"),
    )
)]
async fn update_note(
    _auth: Auth,
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Json(body): Json<UpdateNoteBody>,
) -> Result<impl IntoResponse, ApiError> {
    // Validate chunking parameters (#572)
    validate_chunking_params(body.chunk_max_chars, body.chunk_overlap)
        .map_err(ApiError::BadRequest)?;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let pool = state.db.pool.clone();

    // Update content if provided
    let content_changed = body.content.is_some();
    if let Some(content) = &body.content {
        let notes = matric_db::PgNoteRepository::new(pool.clone());
        let content_clone = content.clone();
        ctx.execute(move |tx| {
            Box::pin(async move { notes.update_original_tx(tx, id, &content_clone).await })
        })
        .await?;
    }

    // Update status if provided
    if body.starred.is_some() || body.archived.is_some() || body.metadata.is_some() {
        let req = UpdateNoteStatusRequest {
            starred: body.starred,
            archived: body.archived,
            metadata: body.metadata,
        };
        let notes = matric_db::PgNoteRepository::new(pool.clone());
        ctx.execute(move |tx| Box::pin(async move { notes.update_status_tx(tx, id, req).await }))
            .await?;
    }

    // Update tags if provided (#226)
    if let Some(tags) = body.tags {
        // Validate tags
        for tag in &tags {
            if tag.len() > matric_core::defaults::TAG_NAME_MAX_LENGTH {
                return Err(tag_length_validation_error(None));
            }
        }
        let repo = matric_db::PgTagRepository::new(pool.clone());
        ctx.execute(move |tx| {
            Box::pin(async move { repo.set_for_note_tx(tx, id, tags, "api").await })
        })
        .await?;
    }

    // Queue full NLP pipeline if content changed
    if content_changed {
        // Parse revision mode (default to Light)
        let revision_mode = match body.revision_mode.as_deref() {
            Some("light") => RevisionMode::Light,
            Some("none") => RevisionMode::None,
            Some("full") | Some("contextual") => RevisionMode::Contextual,
            Some("contextual_filtered") => RevisionMode::ContextualFiltered,
            _ => RevisionMode::Standard,
        };

        // When revision_mode is "none", sync revised content with original for FTS
        // without creating a fake note_revision history entry (#625).
        if revision_mode == RevisionMode::None {
            if let Some(content) = &body.content {
                let notes = matric_db::PgNoteRepository::new(pool.clone());
                let content_clone = content.clone();
                let _ = ctx
                    .execute(move |tx| {
                        Box::pin(async move {
                            notes
                                .sync_revised_to_original_tx(tx, id, &content_clone)
                                .await
                        })
                    })
                    .await;
            }
        }

        // Determine schema for background jobs (Issue #413)
        let schema_for_jobs = if archive_ctx.schema != "public" {
            Some(archive_ctx.schema.as_str())
        } else {
            None
        };
        queue_nlp_pipeline_inner(
            &state.db,
            id,
            revision_mode,
            &state.event_bus,
            schema_for_jobs,
            body.model.as_deref(),
            false,
            body.chunk_max_chars,
            body.chunk_overlap,
            None,
        )
        .await;
    }

    // Fetch and return the updated note
    let notes = matric_db::PgNoteRepository::new(pool);
    let note = ctx
        .query(move |tx| Box::pin(async move { notes.fetch_tx(tx, id).await }))
        .await?;

    // Emit NoteUpdated event (Issue #41, scoped via #452)
    state.event_bus.emit_with_context(
        ServerEvent::NoteUpdated {
            note_id: id,
            title: note.note.title.clone(),
            tags: note.tags.clone(),
            has_ai_content: note.revised.ai_generated_at.is_some(),
            has_links: !note.links.is_empty(),
        },
        event_context_for(&archive_ctx),
    );

    // Invalidate search cache so updated content appears in search results (#341)
    state.search_cache.invalidate_all().await;

    Ok(Json(note))
}

#[utoipa::path(
    delete,
    path = "/api/v1/notes/{id}",
    tag = "Notes",
    params(
        ("id" = Uuid, Path, description = "Note ID")
    ),
    responses(
        (status = 204, description = "Success"),
        (status = 404, description = "Not found"),
    )
)]
async fn delete_note(
    _auth: Auth,
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    ctx.execute(move |tx| Box::pin(async move { notes.soft_delete_tx(tx, id).await }))
        .await?;

    // Emit NoteDeleted event (Issue #453, scoped via #452)
    state.event_bus.emit_with_context(
        ServerEvent::NoteDeleted { note_id: id },
        event_context_for(&archive_ctx),
    );

    // Invalidate search cache so deleted notes don't appear in results (#247)
    state.search_cache.invalidate_all().await;

    Ok(StatusCode::NO_CONTENT)
}

/// Permanently delete a note by queuing a purge job.
/// This triggers CASCADE DELETE on all related data.
#[utoipa::path(
    post,
    path = "/api/v1/notes/{id}/purge",
    tag = "Notes",
    params(
        ("id" = Uuid, Path, description = "Note ID")
    ),
    responses(
        (status = 200, description = "Success"),
        (status = 404, description = "Not found"),
    )
)]
async fn purge_note(
    _auth: Auth,
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    // NOTE: Write scope enforcement removed for pre-tenancy permissive mode.
    // Scope infrastructure kept in place for future multi-tenancy.
    // See: issue #129, commit 49d9f3f

    // Verify note exists first
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let exists = ctx
        .query(move |tx| Box::pin(async move { notes.exists_tx(tx, id).await }))
        .await?;

    if !exists {
        return Err(note_not_found());
    }

    // Queue a high-priority purge job
    let job_id = state
        .db
        .jobs
        .queue(
            Some(id),
            JobType::PurgeNote,
            JobType::PurgeNote.default_priority(),
            None,
            None,
        )
        .await?;

    state.event_bus.emit(ServerEvent::JobQueued {
        job_id,
        job_type: format!("{:?}", JobType::PurgeNote),
        note_id: Some(id),
    });

    // Invalidate search cache (#247)
    state.search_cache.invalidate_all().await;

    Ok(Json(serde_json::json!({
        "status": "queued",
        "job_id": job_id.to_string(),
        "note_id": id.to_string()
    })))
}

#[derive(Debug, Deserialize, utoipa::ToSchema)]
struct UpdateStatusBody {
    starred: Option<bool>,
    archived: Option<bool>,
}

#[utoipa::path(patch, path = "/api/v1/notes/{id}/status", tag = "Notes",
    params(("id" = Uuid, Path, description = "Note ID")),
    request_body = UpdateStatusBody,
    responses(
        (status = 204, description = "Success"),
        (status = 404, description = "Not found"),
    )
)]
async fn update_note_status(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Json(body): Json<UpdateStatusBody>,
) -> Result<impl IntoResponse, ApiError> {
    let archived_value = body.archived;
    let req = UpdateNoteStatusRequest {
        starred: body.starred,
        archived: body.archived,
        metadata: None,
    };
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    ctx.execute(move |tx| Box::pin(async move { notes.update_status_tx(tx, id, req).await }))
        .await?;

    // Emit archive/restore events (Issue #453, scoped via #452)
    let evt_ctx = event_context_for(&archive_ctx);
    match archived_value {
        Some(true) => state
            .event_bus
            .emit_with_context(ServerEvent::NoteArchived { note_id: id }, evt_ctx),
        Some(false) => state
            .event_bus
            .emit_with_context(ServerEvent::NoteRestored { note_id: id }, evt_ctx),
        None => {}
    }

    // Invalidate search cache so status changes are reflected (#341)
    state.search_cache.invalidate_all().await;

    Ok(StatusCode::NO_CONTENT)
}

