#[derive(Deserialize)]
struct GraphQuery {
    /// Maximum depth to traverse (default: 2)
    #[serde(default = "default_depth")]
    depth: i32,
    /// Maximum nodes to return (default: 50)
    #[serde(default = "default_max_nodes")]
    max_nodes: i64,
    /// Minimum edge score threshold (default: 0.0)
    #[serde(default)]
    min_score: f32,
    /// Maximum edges per node (default: unlimited)
    max_edges_per_node: Option<i64>,
    /// Edge community filter (#480): "all" (default), "intra_community", "inter_community"
    edge_filter: Option<String>,
    /// Include structural collection edges (#480, default: true)
    #[serde(default = "default_include_structural")]
    include_structural: bool,
}

impl fmt::Debug for GraphQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("GraphQuery")
            .field("depth", &self.depth)
            .field("max_nodes", &self.max_nodes)
            .field("min_score", &self.min_score)
            .field("max_edges_per_node", &self.max_edges_per_node)
            .field(
                "edge_filter_len",
                &self.edge_filter.as_ref().map(String::len),
            )
            .field("include_structural", &self.include_structural)
            .finish()
    }
}

fn default_include_structural() -> bool {
    true
}

fn default_depth() -> i32 {
    2
}

fn default_max_nodes() -> i64 {
    50
}

#[utoipa::path(get, path = "/api/v1/graph/{id}", tag = "Graph",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn explore_graph(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Query(query): Query<GraphQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;

    // Verify starting note exists (fixes #388)
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let exists = ctx
        .query(move |tx| Box::pin(async move { notes.exists_tx(tx, id).await }))
        .await?;
    if !exists {
        return Err(note_not_found());
    }

    let links = matric_db::PgLinkRepository::new(state.db.pool.clone());
    // Clamp resource limits to prevent DoS (fixes #218, #469)
    let depth = query.depth.clamp(0, 10);
    let max_nodes = query.max_nodes.clamp(1, 1000);
    let min_score = query.min_score.clamp(0.0, 1.0);
    let max_edges_per_node = query.max_edges_per_node.map(|v| v.clamp(1, 1000));
    let edge_filter = query.edge_filter.clone();
    let include_structural = query.include_structural;
    let result = ctx
        .query(move |tx| {
            Box::pin(async move {
                links
                    .traverse_graph_tx(
                        tx,
                        id,
                        depth,
                        max_nodes,
                        min_score,
                        max_edges_per_node,
                        edge_filter.as_deref(),
                        include_structural,
                    )
                    .await
            })
        })
        .await?;
    Ok(Json(result))
}

