/// A single related note with score and relationship source.
#[derive(Serialize)]
struct RelatedNote {
    note_id: Uuid,
    score: f32,
    snippet: Option<String>,
    title: Option<String>,
    tags: Vec<String>,
    /// How this note was discovered: "semantic", "link_outgoing", or "link_incoming".
    source: String,
}

impl std::fmt::Debug for RelatedNote {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("RelatedNote")
            .field("note_id", &self.note_id)
            .field("score", &self.score)
            .field(
                "snippet_len",
                &self.snippet.as_ref().map(|value| value.len()),
            )
            .field("title_len", &self.title.as_ref().map(|value| value.len()))
            .field("tags_count", &self.tags.len())
            .field("source_len", &self.source.len())
            .finish()
    }
}

/// Query parameters for the related-notes endpoint.
#[derive(Debug, Deserialize)]
struct RelatedNotesQuery {
    /// Maximum related notes to return (default: 10, max: 50).
    limit: Option<i64>,
    /// Minimum similarity score threshold (default: 0.3).
    min_score: Option<f32>,
    /// Include an LLM-generated context summary (default: false).
    /// Requires an inference backend to be available.
    context_summary: Option<bool>,
}

/// Response from the related-notes endpoint.
#[derive(Serialize)]
struct RelatedNotesResponse {
    note_id: Uuid,
    related: Vec<RelatedNote>,
    /// LLM-generated explanation of why these notes are related.
    /// Only present when `context_summary=true` and inference is available.
    #[serde(skip_serializing_if = "Option::is_none")]
    context_summary: Option<String>,
}

impl std::fmt::Debug for RelatedNotesResponse {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("RelatedNotesResponse")
            .field("note_id", &self.note_id)
            .field("related_count", &self.related.len())
            .field(
                "context_summary_len",
                &self.context_summary.as_ref().map(|value| value.len()),
            )
            .finish()
    }
}

/// Get related notes via semantic similarity and graph links.
///
/// Combines vector-similarity search (if the note has embeddings) with
/// direct graph links to produce a unified list of related notes,
/// optionally enriched with an LLM-generated context summary.
#[utoipa::path(get, path = "/api/v1/notes/{id}/related", tag = "Graph",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("limit" = Option<i64>, Query, description = "Max results (default 10, max 50)"),
        ("min_score" = Option<f32>, Query, description = "Minimum score threshold (default 0.3)"),
        ("context_summary" = Option<bool>, Query, description = "Include LLM context summary"),
    ),
    responses((status = 200, description = "Related notes")))]
async fn get_related_notes(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Query(query): Query<RelatedNotesQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let pool = state.db.pool.clone();
    let note_id = id;

    let limit = query.limit.unwrap_or(10).clamp(1, 50);
    let min_score = query.min_score.unwrap_or(0.3);
    let want_summary = query.context_summary.unwrap_or(false);

    // 1. Verify note exists
    let notes = matric_db::PgNoteRepository::new(pool.clone());
    let note_exists = ctx
        .query(move |tx| Box::pin(async move { notes.exists_tx(tx, note_id).await }))
        .await?;
    if !note_exists {
        return Err(note_not_found());
    }

    // 2. Get note title for the LLM prompt
    let source_title = {
        let notes = matric_db::PgNoteRepository::new(pool.clone());
        ctx.query(move |tx| {
            Box::pin(async move {
                let full = notes.fetch_tx(tx, note_id).await?;
                Ok(full.note.title.unwrap_or_default())
            })
        })
        .await
        .unwrap_or_default()
    };

    // 3. Find semantically similar notes via embedding vector
    let semantic_hits: Vec<RelatedNote> = {
        let embeds = matric_db::PgEmbeddingRepository::new(pool.clone());
        let embeds2 = matric_db::PgEmbeddingRepository::new(pool.clone());
        // Fetch the note's embedding vector, then find similar
        let hits = ctx
            .query(move |tx| {
                Box::pin(async move {
                    let vec_opt = embeds.get_note_vector_tx(tx, note_id).await?;
                    match vec_opt {
                        Some(vec) => {
                            // Request extra to account for self-exclusion and merging
                            embeds2.find_similar_tx(tx, &vec, limit + 5, true).await
                        }
                        None => Ok(Vec::new()),
                    }
                })
            })
            .await?;

        hits.into_iter()
            .filter(|h| h.note_id != note_id && h.score >= min_score)
            .map(|h| RelatedNote {
                note_id: h.note_id,
                score: h.score,
                snippet: h.snippet,
                title: h.title,
                tags: h.tags,
                source: "semantic".to_string(),
            })
            .collect()
    };

    // 4. Get graph links (outgoing + incoming)
    let link_notes: Vec<RelatedNote> = {
        let links_out = matric_db::PgLinkRepository::new(pool.clone());
        let links_in = matric_db::PgLinkRepository::new(pool.clone());

        let (outgoing, incoming) = ctx
            .query(move |tx| {
                Box::pin(async move {
                    let out = links_out.get_outgoing_tx(tx, note_id).await?;
                    let inc = links_in.get_incoming_tx(tx, note_id).await?;
                    Ok((out, inc))
                })
            })
            .await?;

        let mut link_results: Vec<RelatedNote> = Vec::new();
        for link in outgoing {
            if let Some(to_id) = link.to_note_id {
                if to_id != note_id {
                    link_results.push(RelatedNote {
                        note_id: to_id,
                        score: link.score,
                        snippet: link.snippet,
                        title: None,
                        tags: Vec::new(),
                        source: "link_outgoing".to_string(),
                    });
                }
            }
        }
        for link in incoming {
            if link.from_note_id != note_id {
                link_results.push(RelatedNote {
                    note_id: link.from_note_id,
                    score: link.score,
                    snippet: link.snippet,
                    title: None,
                    tags: Vec::new(),
                    source: "link_incoming".to_string(),
                });
            }
        }
        link_results
    };

    // 5. Merge and deduplicate (prefer semantic over link, keep highest score)
    let mut seen = std::collections::HashMap::<Uuid, usize>::new();
    let mut merged: Vec<RelatedNote> = Vec::new();

    // Add semantic hits first (higher quality — have title, tags, longer snippets)
    for note in semantic_hits {
        seen.insert(note.note_id, merged.len());
        merged.push(note);
    }
    // Add link hits, merging score if already present
    for note in link_notes {
        if let Some(&idx) = seen.get(&note.note_id) {
            // Keep the higher score
            if note.score > merged[idx].score {
                merged[idx].score = note.score;
            }
        } else {
            seen.insert(note.note_id, merged.len());
            merged.push(note);
        }
    }

    // Sort by score descending and truncate to limit
    merged.sort_by(|a, b| {
        b.score
            .partial_cmp(&a.score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    merged.truncate(limit as usize);

    // 6. Optionally generate LLM context summary
    let context_summary = if want_summary && !merged.is_empty() {
        let backend = OllamaBackend::from_env();

        // Build a concise prompt from the related notes
        let mut note_list = String::new();
        for (i, rn) in merged.iter().take(5).enumerate() {
            let title = rn.title.as_deref().unwrap_or("Untitled");
            let snippet = rn
                .snippet
                .as_deref()
                .unwrap_or("")
                .chars()
                .take(120)
                .collect::<String>();
            note_list.push_str(&format!(
                "{}. \"{}\" (score: {:.2}): {}\n",
                i + 1,
                title,
                rn.score,
                snippet
            ));
        }

        let system = "You are a knowledge assistant. Given a source note and its related notes, \
            write a brief 1-2 sentence summary explaining the thematic connection between them. \
            Be specific about the shared topics or concepts. Do not use filler phrases.";
        let prompt = format!(
            "Source note: \"{}\"\n\nRelated notes:\n{}\n\nContext summary:",
            source_title, note_list
        );

        match GenerationBackend::generate_with_system(&backend, system, &prompt).await {
            Ok(summary) => Some(summary.trim().to_string()),
            Err(e) => {
                tracing::warn!(
                    error_len = telemetry_text_len(&e.to_string()),
                    detail = API_RELATED_NOTES_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "generate_related_notes_context_summary",
                    "Failed to generate context summary for related notes"
                );
                None
            }
        }
    } else {
        None
    };

    Ok(Json(RelatedNotesResponse {
        note_id,
        related: merged,
        context_summary,
    }))
}

// =============================================================================
// PROVENANCE HANDLERS (W3C PROV)
// =============================================================================

/// Get W3C PROV provenance chain for a note's AI revisions.
///
/// Returns the full provenance graph including:
/// - Activities (AI processing operations)
/// - Edges (derivation relationships to source notes)
#[utoipa::path(get, path = "/api/v1/notes/{id}/provenance", tag = "Provenance",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn get_note_provenance(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let pool = state.db.pool.clone();
    let note_id = id;

    let chain = {
        let prov = matric_db::PgProvenanceRepository::new(pool.clone());
        ctx.query(move |tx| Box::pin(async move { prov.get_chain_tx(tx, note_id).await }))
            .await?
    };

    let activities = {
        let prov = matric_db::PgProvenanceRepository::new(pool.clone());
        ctx.query(move |tx| {
            Box::pin(async move { prov.get_activities_for_note_tx(tx, note_id).await })
        })
        .await?
    };

    let edges = {
        let prov = matric_db::PgProvenanceRepository::new(pool.clone());
        ctx.query(move |tx| Box::pin(async move { prov.get_edges_for_note_tx(tx, note_id).await }))
            .await?
    };

    let derived = {
        let prov = matric_db::PgProvenanceRepository::new(pool.clone());
        ctx.query(move |tx| Box::pin(async move { prov.get_derived_notes_tx(tx, note_id).await }))
            .await?
    };

    Ok(Json(serde_json::json!({
        "note_id": id,
        "current_chain": chain,
        "all_activities": activities,
        "all_edges": edges,
        "derived_notes": derived,
        "derived_count": derived.len()
    })))
}

// =============================================================================
// MEMORY SEARCH HANDLERS (Spatial/Temporal Provenance)
// =============================================================================

#[derive(Debug, Deserialize)]
struct MemorySearchQuery {
    /// Latitude in decimal degrees (-90 to 90)
    lat: Option<f64>,
    /// Longitude in decimal degrees (-180 to 180)
    lon: Option<f64>,
    /// Search radius in meters (default: 1000)
    radius: Option<f64>,
    /// Start of time range (ISO 8601)
    start: Option<crate::query_types::FlexibleDateTime>,
    /// End of time range (ISO 8601)
    end: Option<crate::query_types::FlexibleDateTime>,
}

/// Search memories by location, time, or both.
///
/// Query parameter combinations:
/// - `lat` + `lon` + `radius` → spatial search (nearest memories)
/// - `start` + `end` → temporal search (memories in time range)
/// - All five → combined spatial + temporal search
#[utoipa::path(get, path = "/api/v1/memories/search", tag = "Search",
    responses((status = 200, description = "Success")))]
async fn search_memories(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<MemorySearchQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let has_location = query.lat.is_some() && query.lon.is_some();
    let has_time = query.start.is_some() && query.end.is_some();

    if !has_location && !has_time {
        return Err(ApiError::BadRequest(
            "At least one search dimension required. Provide lat+lon for spatial search, \
             start+end for temporal search, or all for combined search."
                .to_string(),
        ));
    }

    // Validate coordinate bounds (issue #148)
    if let Some(lat) = query.lat {
        if !(-90.0..=90.0).contains(&lat) {
            return Err(invalid_memory_search_latitude());
        }
    }
    if let Some(lon) = query.lon {
        if !(-180.0..=180.0).contains(&lon) {
            return Err(invalid_memory_search_longitude());
        }
    }
    if let Some(radius) = query.radius {
        if radius <= 0.0 {
            return Err(invalid_memory_search_radius());
        }
    }
    // Return empty results for inverted time ranges (issue #296)
    if has_time {
        let start_dt = query.start.as_ref().unwrap().0;
        let end_dt = query.end.as_ref().unwrap().0;
        if end_dt < start_dt {
            let mode = if has_location { "combined" } else { "time" };
            return Ok(Json(serde_json::json!({
                "mode": mode,
                "results": [],
                "count": 0
            })));
        }
    }

    if has_location && has_time {
        // Combined spatial + temporal search
        let lat = query.lat.unwrap();
        let lon = query.lon.unwrap();
        let radius = query.radius.unwrap_or(1000.0);
        let start = query.start.unwrap().into_inner();
        let end = query.end.unwrap().into_inner();

        let ctx = state.db.for_schema(&archive_ctx.schema)?;
        let memory_search = matric_db::PgMemorySearchRepository::new(state.db.pool.clone());
        let results = ctx
            .query(move |tx| {
                Box::pin(async move {
                    memory_search
                        .search_by_location_and_time_tx(tx, lat, lon, radius, start, end)
                        .await
                })
            })
            .await?;

        Ok(Json(serde_json::json!({
            "mode": "combined",
            "results": results,
            "count": results.len()
        })))
    } else if has_location {
        // Spatial-only search
        let lat = query.lat.unwrap();
        let lon = query.lon.unwrap();
        let radius = query.radius.unwrap_or(1000.0);

        let ctx = state.db.for_schema(&archive_ctx.schema)?;
        let memory_search = matric_db::PgMemorySearchRepository::new(state.db.pool.clone());
        let results = ctx
            .query(move |tx| {
                Box::pin(async move {
                    memory_search
                        .search_by_location_tx(tx, lat, lon, radius)
                        .await
                })
            })
            .await?;

        Ok(Json(serde_json::json!({
            "mode": "location",
            "results": results,
            "count": results.len()
        })))
    } else {
        // Temporal-only search
        let start = query.start.unwrap().into_inner();
        let end = query.end.unwrap().into_inner();

        let ctx = state.db.for_schema(&archive_ctx.schema)?;
        let memory_search = matric_db::PgMemorySearchRepository::new(state.db.pool.clone());
        let results = ctx
            .query(move |tx| {
                Box::pin(async move { memory_search.search_by_timerange_tx(tx, start, end).await })
            })
            .await?;

        Ok(Json(serde_json::json!({
            "mode": "time",
            "results": results,
            "count": results.len()
        })))
    }
}

/// Get the complete file provenance chain for a note's attachments.
///
/// Returns temporal-spatial provenance including location, device, and
/// capture time information for all file attachments.
#[utoipa::path(get, path = "/api/v1/notes/{id}/memory-provenance", tag = "Provenance",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn get_memory_provenance_handler(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let memory_search = matric_db::PgMemorySearchRepository::new(state.db.pool.clone());
    let provenance = ctx
        .query(move |tx| {
            Box::pin(async move { memory_search.get_memory_provenance_tx(tx, id).await })
        })
        .await?;

    match provenance {
        Some(prov) => Ok(Json(serde_json::json!(prov))),
        None => Ok(Json(serde_json::json!({
            "note_id": id,
            "files": []
        }))),
    }
}

