/// Export all notes as a JSON export.
/// Respects X-Fortemi-Memory header for archive-scoped exports (#421).
#[utoipa::path(get, path = "/api/v1/backup/export", tag = "Backup",
    responses((status = 200, description = "Success")))]
async fn backup_export(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<BackupExportQuery>,
) -> Result<impl IntoResponse, ApiError> {
    // Build list request with filters
    let tags = query.tags.map(|t| {
        t.split(',')
            .map(|s| s.trim().to_string())
            .filter(|s| !s.is_empty())
            .collect::<Vec<_>>()
    });

    let mut filter = None;
    if query.starred_only {
        filter = Some("starred".to_string());
    }

    // Schema-scoped transaction for the entire export
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;

    let notes_repo = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let tags_repo = matric_db::PgTagRepository::new(state.db.pool.clone());
    let collections_repo = matric_db::PgCollectionRepository::new(state.db.pool.clone());

    // Fetch all notes (paginated — list_tx caps at 100 per page)
    let mut exported_notes = Vec::new();
    let page_size = 100;
    let mut offset: i64 = 0;

    loop {
        let list_req = ListNotesRequest {
            limit: Some(page_size),
            offset: Some(offset),
            filter: filter.clone(),
            sort_by: Some("created_at".to_string()),
            sort_order: Some("asc".to_string()),
            collection_id: None,
            tags: tags.clone(),
            created_after: query.created_after,
            created_before: query.created_before,
            updated_after: None,
            updated_before: None,
        };
        let notes_response = notes_repo.list_tx(&mut tx, list_req).await?;

        if notes_response.notes.is_empty() {
            break;
        }

        for note in &notes_response.notes {
            if let Ok(full_note) = notes_repo.fetch_tx(&mut tx, note.id).await {
                let note_tags = tags_repo
                    .get_for_note_tx(&mut tx, note.id)
                    .await
                    .unwrap_or_default();
                exported_notes.push(serde_json::json!({
                    "id": full_note.note.id,
                    "title": full_note.note.title,
                    "original_content": full_note.original.content,
                    "revised_content": full_note.revised.content,
                    "format": full_note.note.format,
                    "source": full_note.note.source,
                    "starred": full_note.note.starred,
                    "archived": full_note.note.archived,
                    "collection_id": full_note.note.collection_id,
                    "created_at": full_note.note.created_at_utc,
                    "updated_at": full_note.note.updated_at_utc,
                    "tags": note_tags,
                }));
            }
        }

        if (notes_response.notes.len() as i64) < page_size {
            break;
        }
        offset += page_size;
    }

    // Fetch collections
    let collections = collections_repo
        .list_tx(&mut tx, None)
        .await
        .unwrap_or_default();
    let collections_json: Vec<serde_json::Value> = collections
        .iter()
        .map(|c| {
            serde_json::json!({
                "id": c.id,
                "name": c.name,
                "description": c.description,
                "parent_id": c.parent_id,
                "created_at": c.created_at_utc,
                "note_count": c.note_count,
            })
        })
        .collect();

    // Fetch all tags (extract names)
    let all_tags = tags_repo.list_tx(&mut tx).await.unwrap_or_default();
    let tag_names: Vec<String> = all_tags.iter().map(|t| t.name.clone()).collect();

    // Fetch templates
    let templates_repo = matric_db::PgTemplateRepository::new(state.db.pool.clone());
    let templates = templates_repo.list_tx(&mut tx).await.unwrap_or_default();
    let templates_json: Vec<serde_json::Value> = templates
        .iter()
        .map(|t| {
            serde_json::json!({
                "id": t.id,
                "name": t.name,
                "description": t.description,
                "content": t.content,
                "format": t.format,
                "default_tags": t.default_tags,
                "collection_id": t.collection_id,
                "created_at": t.created_at_utc,
                "updated_at": t.updated_at_utc,
            })
        })
        .collect();

    tx.commit().await.map_err(matric_db::Error::Database)?;

    let response = BackupExportResponse {
        manifest: BackupExportManifest {
            version: "1.0.0".to_string(),
            format: "matric-backup".to_string(),
            created_at: chrono::Utc::now(),
            counts: BackupCounts {
                notes: exported_notes.len(),
                collections: collections_json.len(),
                tags: tag_names.len(),
                templates: templates_json.len(),
            },
        },
        notes: exported_notes,
        collections: collections_json,
        tags: tag_names,
        templates: templates_json,
    };

    Ok(Json(response))
}

/// Download backup as a file attachment.
/// Respects X-Fortemi-Memory header for archive-scoped exports (#421).
#[utoipa::path(get, path = "/api/v1/backup/download", tag = "Backup",
    responses((status = 200, description = "Success")))]
async fn backup_download(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<BackupExportQuery>,
) -> Result<impl IntoResponse, ApiError> {
    // Build list request with filters (same as backup_export)
    let tags = query.tags.map(|t| {
        t.split(',')
            .map(|s| s.trim().to_string())
            .filter(|s| !s.is_empty())
            .collect::<Vec<_>>()
    });

    let mut filter = None;
    if query.starred_only {
        filter = Some("starred".to_string());
    }

    // Schema-scoped transaction for the entire export
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;

    let notes_repo = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let tags_repo = matric_db::PgTagRepository::new(state.db.pool.clone());
    let collections_repo = matric_db::PgCollectionRepository::new(state.db.pool.clone());

    // Fetch all notes (paginated — list_tx caps at 100 per page)
    let mut exported_notes = Vec::new();
    let page_size = 100;
    let mut offset: i64 = 0;

    loop {
        let list_req = ListNotesRequest {
            limit: Some(page_size),
            offset: Some(offset),
            filter: filter.clone(),
            sort_by: Some("created_at".to_string()),
            sort_order: Some("asc".to_string()),
            collection_id: None,
            tags: tags.clone(),
            created_after: query.created_after,
            created_before: query.created_before,
            updated_after: None,
            updated_before: None,
        };
        let notes_response = notes_repo.list_tx(&mut tx, list_req).await?;

        if notes_response.notes.is_empty() {
            break;
        }

        for note in &notes_response.notes {
            if let Ok(full_note) = notes_repo.fetch_tx(&mut tx, note.id).await {
                let note_tags = tags_repo
                    .get_for_note_tx(&mut tx, note.id)
                    .await
                    .unwrap_or_default();
                exported_notes.push(serde_json::json!({
                    "id": full_note.note.id,
                    "title": full_note.note.title,
                    "original_content": full_note.original.content,
                    "revised_content": full_note.revised.content,
                    "format": full_note.note.format,
                    "source": full_note.note.source,
                    "starred": full_note.note.starred,
                    "archived": full_note.note.archived,
                    "collection_id": full_note.note.collection_id,
                    "created_at": full_note.note.created_at_utc,
                    "updated_at": full_note.note.updated_at_utc,
                    "tags": note_tags,
                }));
            }
        }

        if (notes_response.notes.len() as i64) < page_size {
            break;
        }
        offset += page_size;
    }

    // Fetch collections
    let collections = collections_repo
        .list_tx(&mut tx, None)
        .await
        .unwrap_or_default();
    let collections_json: Vec<serde_json::Value> = collections
        .iter()
        .map(|c| {
            serde_json::json!({
                "id": c.id,
                "name": c.name,
                "description": c.description,
                "parent_id": c.parent_id,
                "created_at": c.created_at_utc,
                "note_count": c.note_count,
            })
        })
        .collect();

    // Fetch all tags
    let all_tags = tags_repo.list_tx(&mut tx).await.unwrap_or_default();
    let tag_names: Vec<String> = all_tags.iter().map(|t| t.name.clone()).collect();

    // Fetch templates
    let templates_repo = matric_db::PgTemplateRepository::new(state.db.pool.clone());
    let templates = templates_repo.list_tx(&mut tx).await.unwrap_or_default();
    let templates_json: Vec<serde_json::Value> = templates
        .iter()
        .map(|t| {
            serde_json::json!({
                "id": t.id,
                "name": t.name,
                "description": t.description,
                "content": t.content,
                "format": t.format,
                "default_tags": t.default_tags,
                "collection_id": t.collection_id,
                "created_at": t.created_at_utc,
                "updated_at": t.updated_at_utc,
            })
        })
        .collect();

    tx.commit().await.map_err(matric_db::Error::Database)?;

    let response = BackupExportResponse {
        manifest: BackupExportManifest {
            version: "1.0.0".to_string(),
            format: "matric-backup".to_string(),
            created_at: chrono::Utc::now(),
            counts: BackupCounts {
                notes: exported_notes.len(),
                collections: collections_json.len(),
                tags: tag_names.len(),
                templates: templates_json.len(),
            },
        },
        notes: exported_notes,
        collections: collections_json,
        tags: tag_names,
        templates: templates_json,
    };

    // Serialize to JSON
    let json_content = serde_json::to_string_pretty(&response)
        .map_err(|e| backup_operation_failed("Backup export", "serialize backup JSON", e))?;

    // Generate filename with timestamp
    let timestamp = chrono::Utc::now().format("%Y%m%d-%H%M%S");
    let filename = format!("matric-backup-{}.json", timestamp);

    // Return as downloadable file
    let mut headers = HeaderMap::new();
    headers.insert(
        header::CONTENT_TYPE,
        "application/json; charset=utf-8".parse().unwrap(),
    );
    headers.insert(
        header::CONTENT_DISPOSITION,
        format!("attachment; filename=\"{}\"", filename)
            .parse()
            .unwrap(),
    );

    Ok((StatusCode::OK, headers, json_content))
}

#[derive(Deserialize, utoipa::ToSchema)]
struct BackupImportBody {
    /// The backup data to import
    backup: BackupImportData,
    /// Dry run mode - validate without importing
    #[serde(default)]
    dry_run: bool,
    /// Conflict resolution strategy
    #[serde(default)]
    on_conflict: ConflictStrategy,
    /// When true, skip the NLP pipeline (embeddings, metadata, NER,
    /// linking) for imported notes. Notes land as raw content only —
    /// FTS works immediately, semantic search needs a later backfill.
    /// Default false preserves existing behaviour. Added for #677.
    #[serde(default)]
    defer_inference: bool,
}

