#[derive(Debug, Deserialize, Default, Clone, Copy, utoipa::ToSchema)]
#[serde(rename_all = "lowercase")]
enum ConflictStrategy {
    /// Skip notes that already exist (by ID)
    #[default]
    Skip,
    /// Replace existing notes with imported data
    Replace,
    /// Merge: keep existing, add new
    Merge,
}

#[derive(Serialize)]
struct BackupImportResponse {
    status: String,
    dry_run: bool,
    imported: ImportCounts,
    skipped: ImportCounts,
    errors: Vec<String>,
}

impl std::fmt::Debug for BackupImportResponse {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("BackupImportResponse")
            .field("status_len", &self.status.len())
            .field("dry_run", &self.dry_run)
            .field("imported", &self.imported)
            .field("skipped", &self.skipped)
            .field("errors_count", &self.errors.len())
            .finish()
    }
}

#[derive(Debug, Serialize, Default)]
struct ImportCounts {
    notes: usize,
    collections: usize,
    templates: usize,
}

/// Import a knowledge shard.
/// Respects X-Fortemi-Memory header for archive-scoped imports (#421).
#[utoipa::path(post, path = "/api/v1/backup/import", tag = "Backup",
    request_body = BackupImportBody,
    responses((status = 200, description = "Success")))]
async fn backup_import(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Json(body): Json<BackupImportBody>,
) -> Result<impl IntoResponse, ApiError> {
    use matric_core::CreateNoteRequest;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let schema_for_jobs = if archive_ctx.schema != "public" {
        Some(archive_ctx.schema.clone())
    } else {
        None
    };

    let mut imported = ImportCounts::default();
    let mut skipped = ImportCounts::default();
    let mut errors: Vec<String> = Vec::new();

    // Import notes
    for note_data in &body.backup.notes {
        // Get content (prefer original_content, fall back to content)
        let content = note_data
            .original_content
            .as_ref()
            .or(note_data.content.as_ref())
            .cloned()
            .unwrap_or_default();

        if content.is_empty() {
            errors.push(format!(
                "Note {:?} has no content, skipping",
                note_data
                    .id
                    .or(note_data.title.as_ref().map(|_| Uuid::nil()))
            ));
            skipped.notes += 1;
            continue;
        }

        // Check if note exists (by ID)
        if let Some(id) = note_data.id {
            let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
            let exists = ctx
                .query(move |tx| Box::pin(async move { notes.exists_tx(tx, id).await }))
                .await
                .unwrap_or(false);
            if exists {
                match body.on_conflict {
                    ConflictStrategy::Skip => {
                        skipped.notes += 1;
                        continue;
                    }
                    ConflictStrategy::Replace => {
                        // Delete existing and re-create
                        if !body.dry_run {
                            let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
                            let _ = ctx
                                .execute(move |tx| {
                                    Box::pin(async move { notes.soft_delete_tx(tx, id).await })
                                })
                                .await;
                        }
                    }
                    ConflictStrategy::Merge => {
                        // Keep existing
                        skipped.notes += 1;
                        continue;
                    }
                }
            }
        }

        if !body.dry_run {
            // Create the note
            let req = CreateNoteRequest {
                content,
                format: note_data
                    .format
                    .clone()
                    .unwrap_or_else(|| "markdown".to_string()),
                source: note_data
                    .source
                    .clone()
                    .unwrap_or_else(|| "import".to_string()),
                collection_id: note_data.collection_id,
                tags: note_data.tags.clone(),
                metadata: None,
                document_type_id: None,
                title: note_data.title.clone(),
            };

            let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
            let insert_result = ctx
                .execute(move |tx| Box::pin(async move { notes.insert_tx(tx, req).await }))
                .await;

            match insert_result {
                Ok(new_id) => {
                    // Update status if specified
                    if note_data.starred.unwrap_or(false) || note_data.archived.unwrap_or(false) {
                        let status_req = matric_core::UpdateNoteStatusRequest {
                            starred: note_data.starred,
                            archived: note_data.archived,
                            metadata: None,
                        };
                        let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
                        let _ = ctx
                            .execute(move |tx| {
                                Box::pin(async move {
                                    notes.update_status_tx(tx, new_id, status_req).await
                                })
                            })
                            .await;
                    }

                    // If revised content exists, update it
                    if let Some(revised) = &note_data.revised_content {
                        if !revised.is_empty() {
                            let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
                            let revised = revised.clone();
                            let _ = ctx
                                .execute(move |tx| {
                                    Box::pin(async move {
                                        notes
                                            .update_revised_tx(
                                                tx,
                                                new_id,
                                                &revised,
                                                Some("Imported from backup"),
                                            )
                                            .await
                                    })
                                })
                                .await;
                        }
                    }

                    // Queue NLP pipeline (gated by defer_inference — #677)
                    if !body.defer_inference {
                        queue_nlp_pipeline(
                            &state.db,
                            new_id,
                            RevisionMode::None,
                            &state.event_bus,
                            schema_for_jobs.as_deref(),
                            None,
                        )
                        .await;
                    }

                    imported.notes += 1;
                }
                Err(_) => {
                    errors.push(backup_import_error("Failed to import note."));
                }
            }
        } else {
            imported.notes += 1;
        }
    }

    // Import collections (basic support)
    for coll in &body.backup.collections {
        if let (Some(name), Some(_id)) = (
            coll.get("name").and_then(|v| v.as_str()),
            coll.get("id").and_then(|v| v.as_str()),
        ) {
            if !body.dry_run {
                let description = coll.get("description").and_then(|v| v.as_str());
                let collections = matric_db::PgCollectionRepository::new(state.db.pool.clone());
                let name = name.to_string();
                let desc = description.map(String::from);
                let res = ctx
                    .execute(move |tx| {
                        Box::pin(async move {
                            collections
                                .create_tx(tx, &name, desc.as_deref(), None)
                                .await
                        })
                    })
                    .await;
                match res {
                    Ok(_) => imported.collections += 1,
                    Err(_) => skipped.collections += 1,
                }
            } else {
                imported.collections += 1;
            }
        }
    }

    // Import templates (basic support)
    for tmpl in &body.backup.templates {
        if let (Some(name), Some(content)) = (
            tmpl.get("name").and_then(|v| v.as_str()),
            tmpl.get("content").and_then(|v| v.as_str()),
        ) {
            if !body.dry_run {
                use matric_core::CreateTemplateRequest;
                let req = CreateTemplateRequest {
                    name: name.to_string(),
                    description: tmpl
                        .get("description")
                        .and_then(|v| v.as_str())
                        .map(String::from),
                    content: content.to_string(),
                    format: tmpl
                        .get("format")
                        .and_then(|v| v.as_str())
                        .map(String::from),
                    default_tags: None,
                    collection_id: None,
                };
                let templates = matric_db::PgTemplateRepository::new(state.db.pool.clone());
                let res = ctx
                    .execute(move |tx| Box::pin(async move { templates.create_tx(tx, req).await }))
                    .await;
                match res {
                    Ok(_) => imported.templates += 1,
                    Err(_) => skipped.templates += 1,
                }
            } else {
                imported.templates += 1;
            }
        }
    }

    let status = if errors.is_empty() {
        "success"
    } else {
        "partial"
    };

    Ok(Json(BackupImportResponse {
        status: status.to_string(),
        dry_run: body.dry_run,
        imported,
        skipped,
        errors,
    }))
}

