/// Trigger an immediate database backup using native pg_dump.
///
/// This replaces the previous shell-script-based approach. The backup is created
/// as a compressed .sql.gz file in the backup directory, using the same format
/// as `database_backup_snapshot` but with the `auto_` prefix.
/// Respects X-Fortemi-Memory header for note count metadata (#421).
#[utoipa::path(post, path = "/api/v1/backup/trigger", tag = "Backup",
    responses((status = 200, description = "Success")))]
async fn backup_trigger(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    body: Option<Json<BackupTriggerBody>>,
) -> Result<impl IntoResponse, ApiError> {
    let body = body.map(|b| b.0).unwrap_or(BackupTriggerBody {
        destinations: None,
        dry_run: false,
    });

    let backup_dir =
        std::env::var("BACKUP_DEST").unwrap_or_else(|_| "/var/backups/matric-memory".to_string());

    std::fs::create_dir_all(&backup_dir)
        .map_err(|e| backup_operation_failed("Database backup", "create backup directory", e))?;

    let timestamp = chrono::Utc::now();
    let ts_str = timestamp.format("%Y%m%d_%H%M%S");
    let filename = format!("{}_database_{}.sql.gz", backup_prefix::AUTO, ts_str);
    let path = std::path::Path::new(&backup_dir).join(&filename);

    if body.dry_run {
        return Ok(Json(BackupTriggerResponse {
            status: "dry_run".to_string(),
            output: format!("Would create backup: {}", path.display()),
            timestamp,
        }));
    }

    // Get note count for metadata (schema-scoped)
    let note_count = {
        let ctx = state.db.for_schema(&archive_ctx.schema)?;
        let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
        let list_req = ListNotesRequest {
            limit: Some(1),
            ..Default::default()
        };
        ctx.query(move |tx| Box::pin(async move { notes.list_tx(tx, list_req).await }))
            .await
            .map(|r| r.total)
            .ok()
    };

    // Run pg_dump
    let output = std::process::Command::new("pg_dump")
        .args(["-U", "matric", "-h", "localhost", "matric"])
        .env("PGPASSWORD", "matric")
        .output()
        .map_err(|e| backup_operation_failed("Database backup", "spawn pg_dump", e))?;

    if !output.status.success() {
        return Err(backup_command_failed(
            "Database backup",
            "pg_dump",
            output.status.code(),
            &output.stderr,
        ));
    }

    // Compress and save
    use flate2::write::GzEncoder;
    use flate2::Compression;
    use std::io::Write;

    let file = std::fs::File::create(&path)
        .map_err(|e| backup_operation_failed("Database backup", "create backup file", e))?;
    let mut encoder = GzEncoder::new(file, Compression::default());
    encoder
        .write_all(&output.stdout)
        .map_err(|e| backup_operation_failed("Database backup", "write backup file", e))?;
    encoder
        .finish()
        .map_err(|e| backup_operation_failed("Database backup", "compress backup file", e))?;

    let size = std::fs::metadata(&path).map(|m| m.len()).unwrap_or(0);

    // Save metadata sidecar file
    let mut metadata = BackupMetadata::auto(note_count, None);
    if let Err(e) = metadata.populate_version_info(&state.db.pool).await {
        log_backup_metadata_warning("database_backup", "populate_version_info", e);
    }
    if let Err(e) = metadata.save(&path) {
        log_backup_metadata_warning("database_backup", "save_metadata", e);
    }

    Ok(Json(BackupTriggerResponse {
        status: "success".to_string(),
        output: format!("Backup created: {} ({}).", filename, format_size(size)),
        timestamp,
    }))
}

fn backup_operation_failed(
    operation: &'static str,
    context: &'static str,
    error: impl std::fmt::Display,
) -> ApiError {
    let diagnostic = error.to_string();
    ApiError::OperationFailed {
        operation,
        detail: format!("{context}; error_len={}", diagnostic.len()),
    }
}

fn backup_diagnostic_reason(value: &str) -> &'static str {
    let value = value.to_ascii_lowercase();
    if value.contains("timeout") || value.contains("timed out") {
        "timeout"
    } else if value.contains("permission")
        || value.contains("denied")
        || value.contains("forbidden")
    {
        "permission_denied"
    } else if value.contains("connect") || value.contains("connection") {
        "connection_failed"
    } else if value.contains("not found")
        || value.contains("no such file")
        || value.contains("missing")
    {
        "not_found"
    } else if value.contains("json")
        || value.contains("parse")
        || value.contains("invalid")
        || value.contains("syntax")
    {
        "invalid_data"
    } else if value.contains("database")
        || value.contains("postgres")
        || value.contains("sql")
        || value.contains("schema")
    {
        "database_failed"
    } else {
        "operation_failed"
    }
}

fn log_backup_metadata_warning(
    operation: &'static str,
    phase: &'static str,
    error: impl std::fmt::Display,
) {
    let diagnostic = error.to_string();
    warn!(
        operation,
        phase,
        reason_code = backup_diagnostic_reason(&diagnostic),
        error_len = telemetry_text_len(&diagnostic),
        "backup metadata operation failed"
    );
}

fn backup_archive_not_found() -> ApiError {
    ApiError::NotFound("Backup archive not found.".to_string())
}

fn backup_command_failed(
    operation: &'static str,
    command: &'static str,
    status_code: Option<i32>,
    stderr: &[u8],
) -> ApiError {
    warn!(
        operation,
        command,
        status_code,
        stderr_len = stderr.len(),
        "backup command failed"
    );
    ApiError::OperationFailed {
        operation,
        detail: format!(
            "{} failed; command={command}; status={}; stderr_len={}",
            operation,
            status_code
                .map(|status| status.to_string())
                .unwrap_or_else(|| "terminated".to_string()),
            stderr.len()
        ),
    }
}

fn backup_import_error(message: &'static str) -> String {
    message.to_string()
}

fn backup_restore_issue_message(operation: &'static str, stderr: &[u8]) -> String {
    error!(
        operation,
        stderr_len = stderr.len(),
        "backup restore command completed with errors"
    );
    format!("{operation} completed with issues. Check server logs for diagnostics.")
}

fn log_backup_post_restore_warning(command: &'static str, status_code: Option<i32>, stderr: &[u8]) {
    warn!(
        command,
        status_code,
        stderr_len = stderr.len(),
        "backup post-restore maintenance completed with warnings"
    );
}

