#[derive(Deserialize, utoipa::ToSchema)]
struct ShardImportBody {
    /// Base64-encoded knowledge shard data
    shard_base64: String,
    /// Components to import (comma-separated). If not specified, imports all available.
    include: Option<String>,
    /// Dry run - validate without importing
    #[serde(default)]
    dry_run: bool,
    /// Conflict resolution strategy for notes
    #[serde(default)]
    on_conflict: ConflictStrategy,
    /// Whether to skip embedding regeneration (use imported embeddings)
    #[serde(default)]
    skip_embedding_regen: bool,
}

impl std::fmt::Debug for ShardImportBody {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("ShardImportBody")
            .field("shard_base64_len", &self.shard_base64.len())
            .field(
                "include_len",
                &self.include.as_ref().map(|value| value.len()),
            )
            .field("dry_run", &self.dry_run)
            .field("on_conflict", &self.on_conflict)
            .field("skip_embedding_regen", &self.skip_embedding_regen)
            .finish()
    }
}

/// Import options shared between base64 and multipart shard import handlers.
struct ShardImportOptions {
    include: Option<String>,
    dry_run: bool,
    on_conflict: ConflictStrategy,
    skip_embedding_regen: bool,
}

#[derive(Serialize)]
struct ShardImportResponse {
    status: String,
    manifest: Option<ShardManifest>,
    imported: ShardImportCounts,
    skipped: ShardImportCounts,
    errors: Vec<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    warnings: Vec<String>,
    dry_run: bool,
}

impl std::fmt::Debug for ShardImportResponse {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("ShardImportResponse")
            .field("status_len", &self.status.len())
            .field("manifest_set", &self.manifest.is_some())
            .field("imported", &self.imported)
            .field("skipped", &self.skipped)
            .field("errors_count", &self.errors.len())
            .field("warnings_count", &self.warnings.len())
            .field("dry_run", &self.dry_run)
            .finish()
    }
}

#[derive(Debug, Serialize, Default)]
struct ShardImportCounts {
    notes: usize,
    collections: usize,
    tags: usize,
    templates: usize,
    links: usize,
    embedding_sets: usize,
    embedding_set_members: usize,
    embeddings: usize,
}

/// Import a full knowledge shard from tar.gz.
/// Respects X-Fortemi-Memory header for archive-scoped imports (#421).
#[utoipa::path(post, path = "/api/v1/backup/knowledge-shard/import", tag = "Backup",
    responses((status = 200, description = "Success")))]
async fn knowledge_shard_import(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Json(body): Json<ShardImportBody>,
) -> Result<impl IntoResponse, ApiError> {
    use base64::Engine;

    let shard_bytes = base64::engine::general_purpose::STANDARD
        .decode(&body.shard_base64)
        .map_err(|_| invalid_base64_payload("Invalid base64-encoded shard data."))?;

    let opts = ShardImportOptions {
        include: body.include,
        dry_run: body.dry_run,
        on_conflict: body.on_conflict,
        skip_embedding_regen: body.skip_embedding_regen,
    };

    let result =
        knowledge_shard_import_internal(&state, &shard_bytes, &opts, &archive_ctx.schema).await?;
    Ok(Json(result))
}

/// Query parameters for multipart shard upload.
#[derive(Deserialize)]
struct ShardUploadQuery {
    /// Components to import (comma-separated). If not specified, imports all available.
    include: Option<String>,
    /// Dry run - validate without importing
    #[serde(default)]
    dry_run: bool,
    /// Conflict resolution strategy for notes
    #[serde(default)]
    on_conflict: ConflictStrategy,
    /// Whether to skip embedding regeneration
    #[serde(default)]
    skip_embedding_regen: bool,
}

impl fmt::Debug for ShardUploadQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("ShardUploadQuery")
            .field(
                "include_len",
                &self.include.as_deref().map(telemetry_text_len),
            )
            .field("dry_run", &self.dry_run)
            .field("on_conflict", &self.on_conflict)
            .field("skip_embedding_regen", &self.skip_embedding_regen)
            .finish()
    }
}

/// Import a knowledge shard via multipart file upload.
/// Preferred over the JSON/base64 endpoint for large shards.
#[utoipa::path(post, path = "/api/v1/backup/knowledge-shard/upload", tag = "Backup",
    responses((status = 200, description = "Success")))]
async fn knowledge_shard_import_upload(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<ShardUploadQuery>,
    mut multipart: axum::extract::Multipart,
) -> Result<impl IntoResponse, ApiError> {
    // Read the uploaded shard file
    let mut shard_bytes: Option<Vec<u8>> = None;

    while let Some(field) = multipart
        .next_field()
        .await
        .map_err(|_| ApiError::BadRequest("Invalid multipart upload request.".to_string()))?
    {
        if field.name() == Some("file") || field.name() == Some("shard") {
            shard_bytes = Some(
                field
                    .bytes()
                    .await
                    .map_err(|_| ApiError::BadRequest("Invalid uploaded shard data.".to_string()))?
                    .to_vec(),
            );
            break;
        }
    }

    let shard_bytes = shard_bytes.ok_or_else(|| {
        ApiError::BadRequest("No file uploaded. Use field name 'file' or 'shard'.".to_string())
    })?;

    let opts = ShardImportOptions {
        include: query.include,
        dry_run: query.dry_run,
        on_conflict: query.on_conflict,
        skip_embedding_regen: query.skip_embedding_regen,
    };

    let result =
        knowledge_shard_import_internal(&state, &shard_bytes, &opts, &archive_ctx.schema).await?;
    Ok(Json(result))
}

