#[derive(Debug, Serialize, utoipa::ToSchema)]
struct ProblemTypeCatalogEntry {
    type_uri: String,
    status: u16,
    title: String,
    description: String,
}

fn problem_type_catalog_entries() -> Vec<ProblemTypeCatalogEntry> {
    ProblemType::ALL
        .iter()
        .map(|problem_type| ProblemTypeCatalogEntry {
            type_uri: problem_type.type_uri(),
            status: problem_type.status().as_u16(),
            title: problem_type.title().to_string(),
            description: problem_type.description().to_string(),
        })
        .collect()
}

fn problem_response(
    status: StatusCode,
    problem_type: ProblemType,
    detail: String,
    attachment_id: Option<Uuid>,
) -> axum::response::Response {
    let mut problem = ProblemDetails::new(problem_type, status, detail);
    problem.attachment_id = attachment_id;

    (
        status,
        [(header::CONTENT_TYPE, "application/problem+json")],
        Json(problem),
    )
        .into_response()
}

impl From<matric_core::Error> for ApiError {
    fn from(err: matric_core::Error) -> Self {
        match &err {
            matric_core::Error::NotFound(msg) => ApiError::NotFound(msg.clone()),
            matric_core::Error::InvalidInput(msg) => ApiError::BadRequest(msg.clone()),
            matric_core::Error::Database(sqlx_err) => {
                let msg = sqlx_err.to_string();
                if msg.contains("duplicate key") || msg.contains("unique constraint") {
                    // Provide user-friendly error messages for known constraints
                    let friendly_msg =
                        if msg.contains("idx_unique_pref_label") || msg.contains("pref_label") {
                            "A concept with this prefLabel already exists in the scheme".to_string()
                        } else if msg.contains("valid_notation") || msg.contains("notation") {
                            "A concept with this notation already exists in the scheme".to_string()
                        } else if msg.contains("idx_unique_tag_name") || msg.contains("tag_name") {
                            "A tag with this name already exists".to_string()
                        } else if msg.contains("collection_name_key")
                            || msg.contains("collection") && msg.contains("unique")
                        {
                            "A collection with this name already exists".to_string()
                        } else {
                            // Generic friendly message - never expose raw constraint names
                            "A record with this value already exists".to_string()
                        };
                    return ApiError::Conflict(friendly_msg);
                }
                if msg.contains("Polyhierarchy limit") {
                    return ApiError::BadRequest(msg);
                }
                if msg.contains("foreign key") {
                    // Provide user-friendly messages for FK violations
                    let friendly_msg = if msg.contains("job_queue_note_id_fkey")
                        || msg.contains("job_queue") && msg.contains("note")
                    {
                        "Note not found".to_string()
                    } else if msg.contains("note_tag") {
                        "Referenced note or tag not found".to_string()
                    } else {
                        "Referenced resource not found".to_string()
                    };
                    return ApiError::BadRequest(friendly_msg);
                }
                ApiError::Database(err)
            }
            _ => ApiError::Database(err),
        }
    }
}

impl IntoResponse for ApiError {
    fn into_response(self) -> axum::response::Response {
        let (status, problem_type, detail, attachment_id) = match self {
            ApiError::Database(err) => {
                error!(
                    error_len = telemetry_text_len(&err.to_string()),
                    detail = API_DATABASE_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "map_api_database_error",
                    "database error mapped to problem response"
                );
                (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    ProblemType::Internal,
                    "An internal error occurred.".to_string(),
                    None,
                )
            }
            ApiError::Unauthorized(msg) => (
                StatusCode::UNAUTHORIZED,
                ProblemType::Unauthorized,
                msg,
                None,
            ),
            ApiError::Forbidden(msg) => (StatusCode::FORBIDDEN, ProblemType::Forbidden, msg, None),
            ApiError::NotFound(msg) => (StatusCode::NOT_FOUND, ProblemType::NotFound, msg, None),
            ApiError::Gone(msg) => (StatusCode::GONE, ProblemType::Gone, msg, None),
            ApiError::BadRequest(msg) => {
                (StatusCode::BAD_REQUEST, ProblemType::Validation, msg, None)
            }
            ApiError::Conflict(msg) => (StatusCode::CONFLICT, ProblemType::Conflict, msg, None),
            ApiError::Internal(msg) => {
                error!(
                    error_len = telemetry_text_len(&msg),
                    detail = API_INTERNAL_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "map_api_internal_error",
                    "internal error mapped to problem response"
                );
                (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    ProblemType::Internal,
                    "An internal error occurred.".to_string(),
                    None,
                )
            }
            ApiError::OperationFailed { operation, detail } => {
                error!(
                    operation,
                    error_len = telemetry_text_len(&detail),
                    detail = API_OPERATION_DIAGNOSTIC_FAILURE_DETAIL,
                    "operation failure mapped to problem response"
                );
                (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    ProblemType::OperationFailed,
                    format!("{operation} failed. Check server logs for diagnostics."),
                    None,
                )
            }
            ApiError::ProviderFailure { capability, detail } => {
                error!(
                    capability,
                    error_len = telemetry_text_len(&detail),
                    detail = API_PROVIDER_DIAGNOSTIC_FAILURE_DETAIL,
                    "provider failure mapped to problem response"
                );
                (
                    StatusCode::BAD_GATEWAY,
                    ProblemType::ProviderFailure,
                    format!("{capability} provider failed. Check server logs for diagnostics."),
                    None,
                )
            }
            ApiError::ServiceUnavailable(msg) => (
                StatusCode::SERVICE_UNAVAILABLE,
                ProblemType::ServiceUnavailable,
                msg,
                None,
            ),
            ApiError::BlobMissing {
                attachment_id,
                expected_path,
                storage_backend,
            } => {
                error!(
                    attachment_id_present = true,
                    expected_path_len = telemetry_text_len(&expected_path),
                    storage_backend_len = telemetry_text_len(&storage_backend),
                    detail = API_BLOB_MISSING_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "map_attachment_blob_missing",
                    "attachment blob missing"
                );
                (
                    StatusCode::NOT_FOUND,
                    ProblemType::BlobMissing,
                    "Attachment content is no longer available.".to_string(),
                    Some(attachment_id),
                )
            }
        };

        problem_response(status, problem_type, detail, attachment_id)
    }
}

