    #[test]
    fn job_response_redacts_payload_result_and_error_message() {
        let job = Job {
            id: Uuid::parse_str("018fd1a0-0000-7000-8000-000000000801").unwrap(),
            note_id: Some(Uuid::parse_str("018fd1a0-0000-7000-8000-000000000802").unwrap()),
            job_type: JobType::AiRevision,
            status: JobStatus::Failed,
            priority: 10,
            payload: Some(serde_json::json!({
                "input": "uploaded note body with private content",
                "provider_url": "https://token:secret@provider.internal/v1",
                "safe_flag": true,
                "nested": {
                    "prompt": "summarize /home/operator/private.md",
                    "model": "qwen3:8b"
                }
            })),
            result: Some(serde_json::json!({
                "stderr": "pg_dump: connection failed for postgres://user:secret@db/app",
                "summary": "Generated output",
                "items": [
                    {"path": "/srv/fortemi/storage/private.wav"},
                    {"label": "safe"}
                ]
            })),
            error_message: Some(
                "Generation failed: Cannot reach https://token:secret@ollama.internal:11434"
                    .to_string(),
            ),
            progress_percent: 50,
            progress_message: Some("failed".to_string()),
            retry_count: 1,
            max_retries: 3,
            created_at: Utc::now(),
            started_at: Some(Utc::now()),
            completed_at: Some(Utc::now()),
            cost_tier: Some(1),
        };

        let response = JobResponse::from(job);
        let debug = format!("{response:?}");
        let response = serde_json::to_value(response).unwrap();

        assert_eq!(response["payload"]["input"], "[redacted]");
        assert_eq!(response["payload"]["provider_url"], "[redacted]");
        assert_eq!(response["payload"]["nested"]["prompt"], "[redacted]");
        assert_eq!(response["payload"]["nested"]["model"], "qwen3:8b");
        assert_eq!(response["payload"]["safe_flag"], true);
        assert_eq!(response["result"]["stderr"], "[redacted]");
        assert_eq!(response["result"]["items"][0]["path"], "[redacted]");
        assert_eq!(response["result"]["items"][1]["label"], "safe");
        assert_eq!(
            response["error_message"],
            "Job failed. Check server logs for diagnostics."
        );

        let serialized = response.to_string();
        for forbidden in [
            "018fd1a0-0000-7000-8000-000000000801",
            "018fd1a0-0000-7000-8000-000000000802",
            "uploaded note body",
            "token:secret",
            "postgres://",
            "/srv/fortemi",
            "/home/operator",
            "Cannot reach",
            "Generation failed",
        ] {
            assert!(
                !debug.contains(forbidden),
                "job response debug leaked {forbidden}"
            );
        }

        for forbidden in [
            "uploaded note body",
            "token:secret",
            "postgres://",
            "/srv/fortemi",
            "/home/operator",
            "Cannot reach",
            "Generation failed",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "job response leaked {forbidden}"
            );
        }

        assert!(debug.contains("id_present"));
        assert!(debug.contains("note_id_present"));
        assert!(debug.contains("payload_class"));
        assert!(debug.contains("payload_len"));
        assert!(debug.contains("result_class"));
        assert!(debug.contains("result_len"));
        assert!(debug.contains("error_message_len"));
        assert!(debug.contains("progress_message_len"));
    }

