    #[tokio::test]
    async fn problem_request_id_middleware_adds_x_request_id_extension() {
        let mut response = ApiError::Internal("db detail".to_string()).into_response();
        response
            .headers_mut()
            .insert("x-request-id", "018fd1a0-test-request".parse().unwrap());

        let response = inject_request_id_into_problem_response(response).await;
        let problem = read_response_json(response).await;

        assert_eq!(problem["request_id"], "018fd1a0-test-request");
        assert_eq!(
            problem["type"],
            "https://fortemi.com/problems/internal-error"
        );
        assert_eq!(problem["detail"], "An internal error occurred.");
    }

    #[tokio::test]
    async fn problem_request_id_middleware_preserves_existing_request_id() {
        let mut response = (
            StatusCode::BAD_REQUEST,
            [(header::CONTENT_TYPE, "application/problem+json")],
            Json(serde_json::json!({
                "type": "https://fortemi.com/problems/validation-error",
                "title": "Bad Request",
                "status": 400,
                "detail": "Invalid request.",
                "request_id": "existing-request-id"
            })),
        )
            .into_response();
        response
            .headers_mut()
            .insert("x-request-id", "replacement-request-id".parse().unwrap());

        let response = inject_request_id_into_problem_response(response).await;
        let problem = read_response_json(response).await;

        assert_eq!(problem["request_id"], "existing-request-id");
    }

    #[tokio::test]
    async fn problem_request_id_middleware_ignores_non_problem_json() {
        let mut response = Json(serde_json::json!({"ok": true})).into_response();
        response
            .headers_mut()
            .insert("x-request-id", "018fd1a0-test-request".parse().unwrap());

        let response = inject_request_id_into_problem_response(response).await;
        let body = axum::body::to_bytes(response.into_body(), usize::MAX)
            .await
            .unwrap();
        let parsed: serde_json::Value = serde_json::from_slice(&body).unwrap();

        assert_eq!(parsed, serde_json::json!({"ok": true}));
    }

    #[tokio::test]
    async fn route_error_boundary_returns_problem_with_request_id_and_security_headers() {
        let router = Router::new()
            .route(
                "/api/v1/problem-contract-test",
                get(route_problem_contract_test_handler),
            )
            .layer(PropagateRequestIdLayer::x_request_id())
            .layer(SetRequestIdLayer::x_request_id(MakeRequestUuidV7))
            .layer(axum::middleware::from_fn(problem_request_id_middleware))
            .layer(axum::middleware::from_fn(security_headers_middleware));
        let listener = tokio::net::TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind problem contract test server");
        let url = format!(
            "http://{}/api/v1/problem-contract-test",
            listener.local_addr().unwrap()
        );
        tokio::spawn(async move {
            axum::serve(listener, router).await.unwrap();
        });

        let response = reqwest::Client::new()
            .get(url)
            .header("x-request-id", "018fd1a0-route-contract")
            .send()
            .await
            .expect("send problem route request");

        assert_eq!(
            response.status(),
            reqwest::StatusCode::INTERNAL_SERVER_ERROR
        );
        let headers = response.headers().clone();
        assert_eq!(
            headers.get(reqwest::header::CONTENT_TYPE).unwrap(),
            "application/problem+json"
        );
        assert_eq!(
            headers.get(reqwest::header::CACHE_CONTROL).unwrap(),
            "no-store"
        );
        assert_eq!(headers.get("x-content-type-options").unwrap(), "nosniff");
        assert_eq!(headers.get("x-frame-options").unwrap(), "DENY");
        assert_eq!(
            headers.get("content-security-policy").unwrap(),
            "default-src 'none'; frame-ancestors 'none'"
        );

        let problem: serde_json::Value = response.json().await.expect("problem JSON body");
        assert_eq!(
            problem["type"],
            "https://fortemi.com/problems/internal-error"
        );
        assert_eq!(problem["status"], 500);
        assert_eq!(problem["detail"], "An internal error occurred.");
        assert_eq!(problem["request_id"], "018fd1a0-route-contract");
        assert!(problem.get("error").is_none());
        assert!(problem.get("error_description").is_none());

        let body = problem.to_string();
        assert!(!body.contains("postgres://"));
        assert!(!body.contains("secret"));
        assert!(!body.contains("db.internal"));
        assert!(!body.contains("/srv/fortemi"));
    }

    #[tokio::test]
    async fn route_error_boundary_covers_representative_problem_statuses() {
        let router = Router::new()
            .route(
                "/api/v1/problem-contract-status/{status}",
                get(route_problem_contract_status_handler),
            )
            .layer(PropagateRequestIdLayer::x_request_id())
            .layer(SetRequestIdLayer::x_request_id(MakeRequestUuidV7))
            .layer(axum::middleware::from_fn(problem_request_id_middleware))
            .layer(axum::middleware::from_fn(security_headers_middleware));
        let listener = tokio::net::TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind problem status contract test server");
        let base_url = format!("http://{}", listener.local_addr().unwrap());
        tokio::spawn(async move {
            axum::serve(listener, router).await.unwrap();
        });

        let client = reqwest::Client::new();
        for (status, problem_type) in [
            (400_u16, "https://fortemi.com/problems/validation-error"),
            (401, "https://fortemi.com/problems/unauthorized"),
            (403, "https://fortemi.com/problems/forbidden"),
            (404, "https://fortemi.com/problems/not-found"),
            (409, "https://fortemi.com/problems/conflict"),
            (429, "https://fortemi.com/problems/rate-limit-exceeded"),
            (500, "https://fortemi.com/problems/internal-error"),
            (503, "https://fortemi.com/problems/service-unavailable"),
        ] {
            let request_id = format!("018fd1a0-status-{status}");
            let response = client
                .get(format!(
                    "{base_url}/api/v1/problem-contract-status/{status}"
                ))
                .header("x-request-id", &request_id)
                .send()
                .await
                .expect("send problem status route request");

            assert_eq!(response.status().as_u16(), status);
            let headers = response.headers().clone();
            assert_eq!(
                headers.get(reqwest::header::CONTENT_TYPE).unwrap(),
                "application/problem+json"
            );
            assert_eq!(
                headers.get(reqwest::header::CACHE_CONTROL).unwrap(),
                "no-store"
            );
            assert_eq!(headers.get("x-content-type-options").unwrap(), "nosniff");
            assert_eq!(headers.get("x-frame-options").unwrap(), "DENY");

            let problem: serde_json::Value = response.json().await.expect("problem JSON body");
            assert_eq!(problem["type"], problem_type);
            assert_eq!(problem["status"], status);
            assert_eq!(problem["request_id"], request_id);
            assert!(problem.get("error").is_none());
            assert!(problem.get("error_description").is_none());

            let body = problem.to_string();
            assert!(!body.contains("postgres://"));
            assert!(!body.contains("secret"));
            assert!(!body.contains("db.internal"));
            assert!(!body.contains("/srv/fortemi"));
        }
    }

    #[test]
    fn security_headers_for_api_problem_are_private_and_framing_protected() {
        let mut response = problem_response(
            StatusCode::INTERNAL_SERVER_ERROR,
            ProblemType::Internal,
            "An internal error occurred.".to_string(),
            None,
        );

        apply_security_headers("/api/v1/notes", &mut response);
        let headers = response.headers();

        assert_eq!(headers["x-content-type-options"], "nosniff");
        assert_eq!(headers["referrer-policy"], "no-referrer");
        assert_eq!(headers["x-frame-options"], "DENY");
        assert_eq!(
            headers["content-security-policy"],
            "default-src 'none'; frame-ancestors 'none'"
        );
        assert_eq!(headers[header::CACHE_CONTROL], "no-store");
    }

    #[test]
    fn security_headers_for_browser_docs_include_document_csp() {
        let mut response = (
            StatusCode::OK,
            [(header::CONTENT_TYPE, "text/html; charset=utf-8")],
            "<html></html>",
        )
            .into_response();

        apply_security_headers("/docs", &mut response);
        let headers = response.headers();

        assert_eq!(headers["x-content-type-options"], "nosniff");
        assert_eq!(headers["x-frame-options"], "DENY");
        assert_eq!(
            headers["content-security-policy"],
            "default-src 'self'; frame-ancestors 'none'"
        );
        assert_eq!(headers["cross-origin-opener-policy"], "same-origin");
    }

    #[test]
    fn security_headers_for_downloads_do_not_apply_document_csp() {
        let mut response = (
            StatusCode::OK,
            [
                (header::CONTENT_TYPE, "audio/wav"),
                (
                    header::CONTENT_DISPOSITION,
                    "attachment; filename=\"clip.wav\"",
                ),
            ],
            vec![0_u8; 16],
        )
            .into_response();

        apply_security_headers(
            "/api/v1/attachments/018fd1a0-0000-7000-8000-000000000002/download",
            &mut response,
        );
        let headers = response.headers();

        assert_eq!(headers["x-content-type-options"], "nosniff");
        assert_eq!(headers["referrer-policy"], "no-referrer");
        assert_eq!(headers["cross-origin-resource-policy"], "same-origin");
        assert!(!headers.contains_key("content-security-policy"));
        assert!(!headers.contains_key("x-frame-options"));
    }

