    #[tokio::test]
    async fn test_api_key_list_is_metadata_only_after_one_time_create() {
        let (base_url, _bus, _conns) = spawn_eventing_test_server().await;
        let client = reqwest::Client::new();

        let create_resp = client
            .post(format!("{}/api/v1/api-keys", base_url))
            .json(&serde_json::json!({
                "name": "operator-key-secret-label",
                "description": "description with api_key=metadata-secret",
                "scope": "admin secret-scope-marker"
            }))
            .send()
            .await
            .unwrap();
        assert_eq!(create_resp.status(), 201);
        let created: serde_json::Value = create_resp.json().await.unwrap();
        let key_id = created["id"].as_str().unwrap().to_string();
        let full_key = created["api_key"].as_str().unwrap().to_string();
        let key_prefix = created["key_prefix"].as_str().unwrap().to_string();

        assert!(full_key.starts_with("mm_key_"));
        assert!(!key_prefix.is_empty());

        let list_resp = client
            .get(format!("{}/api/v1/api-keys", base_url))
            .send()
            .await
            .unwrap();
        assert_eq!(list_resp.status(), 200);
        let listed: serde_json::Value = list_resp.json().await.unwrap();
        let keys = listed["api_keys"].as_array().unwrap();
        let listed_key = keys
            .iter()
            .find(|key| key["id"].as_str() == Some(key_id.as_str()))
            .expect("created API key should be listed");

        assert_eq!(
            listed_key["key_prefix_len"].as_u64().unwrap(),
            key_prefix.chars().count() as u64
        );
        assert_eq!(
            listed_key["name_len"].as_u64().unwrap(),
            "operator-key-secret-label".chars().count() as u64
        );
        assert_eq!(
            listed_key["description_len"].as_u64().unwrap(),
            "description with api_key=metadata-secret".chars().count() as u64
        );
        assert_eq!(
            listed_key["scope_len"].as_u64().unwrap(),
            "admin secret-scope-marker".chars().count() as u64
        );

        let serialized = serde_json::to_string(&listed).unwrap();
        for forbidden in [
            full_key.as_str(),
            key_prefix.as_str(),
            "mm_key_",
            "operator-key-secret-label",
            "metadata-secret",
            "secret-scope-marker",
            "\"api_key\"",
            "\"key_prefix\"",
            "\"name\"",
            "\"description\"",
            "\"scope\"",
            "key_hash",
            "Bearer",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "API key list response leaked {forbidden}: {serialized}"
            );
        }

        let delete_resp = client
            .delete(format!("{}/api/v1/api-keys/{}", base_url, key_id))
            .send()
            .await
            .unwrap();
        assert_eq!(delete_resp.status(), 204);
    }

    #[tokio::test]
    async fn test_inbound_source_list_is_metadata_only() {
        let (base_url, _bus, _conns) = spawn_eventing_test_server().await;
        let client = reqwest::Client::new();
        let source_name = format!("source-secret-name-{}", Uuid::new_v4().simple());

        let create_resp = client
            .post(format!("{}/api/v1/inbound-sources", base_url))
            .json(&serde_json::json!({
                "name": source_name,
                "kind": "sse",
                "enabled": true,
                "config": {
                    "url": "https://user:pass@provider.example/stream?api_key=inbound-secret-token",
                    "headers": {
                        "Authorization": "Bearer inbound-secret-token",
                        "X-Api-Key": "inbound-api-key-secret"
                    },
                    "event_type_field": "tenant_secret_event_type",
                    "default_event_type": "secret.default.v1",
                    "event_type_filter": ["tenant.secret.v1"]
                }
            }))
            .send()
            .await
            .unwrap();
        assert_eq!(create_resp.status(), 201);
        let created: serde_json::Value = create_resp.json().await.unwrap();
        let source_id = created["id"].as_str().unwrap().to_string();

        let list_resp = client
            .get(format!("{}/api/v1/inbound-sources", base_url))
            .send()
            .await
            .unwrap();
        assert_eq!(list_resp.status(), 200);
        let listed: serde_json::Value = list_resp.json().await.unwrap();
        let sources = listed.as_array().unwrap();
        let listed_source = sources
            .iter()
            .find(|source| source["id"].as_str() == Some(source_id.as_str()))
            .expect("created inbound source should be listed");

        assert_eq!(
            listed_source["name_len"].as_u64().unwrap(),
            source_name.chars().count() as u64
        );
        assert_eq!(listed_source["kind_len"].as_u64().unwrap(), 3);
        assert_eq!(listed_source["config_class"], "object");
        assert_eq!(listed_source["config_secret_candidate"], true);
        assert_eq!(listed_source["config_key_count"].as_u64().unwrap(), 5);
        assert!(listed_source["config_len"].as_u64().unwrap() > 0);
        assert_eq!(listed_source["enabled"], true);

        let serialized = serde_json::to_string(&listed).unwrap();
        for forbidden in [
            "source-secret-name",
            "\"name\"",
            "\"kind\"",
            "\"config\"",
            "https://user:pass@provider.example",
            "api_key=inbound-secret-token",
            "Authorization",
            "Bearer inbound-secret-token",
            "X-Api-Key",
            "inbound-api-key-secret",
            "tenant_secret_event_type",
            "secret.default.v1",
            "tenant.secret.v1",
        ] {
            assert!(
                !serialized.contains(forbidden),
                "inbound source list response leaked {forbidden}: {serialized}"
            );
        }

        let delete_resp = client
            .delete(format!(
                "{}/api/v1/inbound-sources/{}",
                base_url, source_name
            ))
            .send()
            .await
            .unwrap();
        assert_eq!(delete_resp.status(), 204);
    }

